// Type definitions
export interface DataPointConfig {
  fixed?: number
  timeFormat?: {
    hasFormat?: boolean
    format?: string
  }
  valFormat?: 'round' | 'carryUp' | 'slice' | 'hexadecimal' | 'scientific' | 'script'
  formatScript?: string
  polish?: boolean
  tagValue?: {
    enum?: Array<{
      value: any
      label?: string
      label_en?: string
      label_zh?: string
      regex?: string
    }>
  }
  interval?: number
  errview?: string
}

// Utility Functions

/**
 * Ceiling number calculation
 * 向上进位计算
 */
export const ceilNum = (d: number, prex: number): number => {
  if (parseInt(d.toString()) == d) return d
  let len = 1
  let i = 0
  while (parseInt(d.toString()) != d) {
    d = d * 10
    len *= 10
    i++
  }
  const last = Math.abs(i <= prex ? 0 : d % (Math.pow(10, (i - prex))))
  let d1 = d - last
  if (last > 0) {
    d1 = d1 + Math.pow(10, (i - prex))
  }
  d1 = d1 / len
  return d1
}

/**
 * Number slicing by decimal places
 * 按位截断数字
 */
export const sliceNum = (number: number, fixed: number): number => {
  const indexOfDecimal = String(number).indexOf('.')
  const sliceEnd = indexOfDecimal !== -1 ? indexOfDecimal + fixed + 1 : undefined
  const slicedNumber = sliceEnd !== undefined ? String(number).slice(0, sliceEnd) : String(number)
  return Number(slicedNumber)
}

/**
 * Fixed decimal formatting
 * 固定小数位数格式化
 */
export const toFixed = (Dight: number | string, How: number = 2, polish?: boolean): number | string => {
  const v = _.isNumber(Dight) ? Math.round(Number(Dight) * Math.pow(10, How)) / Math.pow(10, How) : Dight
  const pv = (val: number | string): string => {
    const n = val.toString().split('.')
    if (n.length == 1) {
      return val + `${How > 0 ? '.' + _.padEnd('', How, '0') : ''}`
    } else {
      const decimal = n[1]
      return val + _.padEnd('', How - decimal.length, '0')
    }
  }
  return _.isNaN(Number(v)) ? Dight : polish ? pv(v) : v
}

/**
 * Convert number to scientific notation
 * 科学计数法转换
 */
export const scientificNotation = (number: number): string => {
  return number.toExponential()
}

/**
 * Convert number to hexadecimal
 * 十六进制转换
 */
export const numberToHex = (value: number): string => {
  if (typeof value !== 'number') {
    return String(value)
  }

  const integerValue = Math.floor(value)
  const fractionalValue = value - integerValue

  const hexInteger = integerValue.toString(16)

  if (fractionalValue === 0) {
    return hexInteger
  }

  let hexFractional = ''
  const maxFractionalDigits = 6
  let currentFractionalValue = fractionalValue

  while (currentFractionalValue !== 0 && hexFractional.length < maxFractionalDigits) {
    currentFractionalValue *= 16
    const digit = Math.floor(currentFractionalValue)
    hexFractional += digit.toString(16)
    currentFractionalValue -= digit
  }

  return `${hexInteger}.${hexFractional}`
}

/**
 * Format value using custom script
 * 使用自定义脚本格式化值
 */
export const valueFormatScript = (number: number, script: string): any => {
  try {
    return eval(script)(number)
  } catch (error) {
    console.log(error)
    return number
  }
}

/**
 * Value formatting with multiple options
 * 值格式化（支持多种格式）
 * @param val - The value to format
 * @param fixed - Number of decimal places
 * @param valFormat - Format type: 'round' | 'carryUp' | 'slice' | 'hexadecimal' | 'scientific' | 'script'
 * @param formatScript - Custom script for formatting
 * @param polish - Whether to pad with zeros
 */
export const valueFormat = (
  val: any,
  fixed?: number,
  valFormat?: string,
  formatScript?: string,
  polish?: boolean
): any => {
  if (_.isNil(val)) return val
  if (valFormat == 'slice') {
    return _.isNumber(val) && _.isNumber(fixed) ? sliceNum(val, fixed) : val
  } else if (valFormat == 'carryUp') {
    return _.isNumber(val) ? ceilNum(val, fixed || 0) : val
  } else {
    const fixedValue = fixed !== undefined ? toFixed(val, fixed, polish) : val
    if (valFormat == 'hexadecimal') {
      return numberToHex(Number(fixedValue))
    } else if (valFormat == 'scientific') {
      return scientificNotation(Number(fixedValue))
    } else if (valFormat == 'script') {
      return valueFormatScript(Number(val), formatScript || '')
    } else {
      return fixedValue
    }
  }
}

/**
 * Convert value with config-based formatting
 * 根据配置转换值
 * @param value - The value to convert
 * @param format - Custom format function
 * @param config - DataPoint configuration
 */
export const convertValue = (
  value: any,
  format?: (value: any) => any,
  config?: DataPointConfig
): any => {
  if (!config) return value

  const { tagValue, fixed, timeFormat, valFormat, formatScript, polish } = config

  let val = value
  if (_.isNil(val)) return val

  // Handle enum values (dropdown type data)
  const language = 'zh' // Default to Chinese, could be made configurable via prop
  if (tagValue && tagValue.enum && _.isArray(tagValue.enum)) {
    tagValue.enum.forEach(o => {
      if (o.value == val) {
        val = o[`label_${language}`] || o.label
      }
      if (o.regex && o.label) {
        val = val + ''
        const lastCommaIndex = _.lastIndexOf(o.label, ',')
        if (lastCommaIndex !== -1) {
          const regex = new RegExp(o.label.slice(0, lastCommaIndex))
          val = val?.replace(regex, o.label.slice(lastCommaIndex + 1))
        }
      }
    })
  }

  // Handle timestamp formatting
  if (timeFormat?.hasFormat && timeFormat?.format) {
    val = dayjs(val).format(timeFormat?.format)
  }

  // Handle value formatting
  if (valFormat || polish) {
    val = valueFormat(val, fixed, valFormat, formatScript, polish)
  }

  if (format && _.isFunction(format)) {
    val = format(val)
  }

  return val
}

import _ from 'lodash'
import React from 'react'
import dayjs from 'dayjs'
import { BaseChart, BaseChartProps } from '@/registry/components/chart-echarts/BaseChart'
import { createAPI, getSettings } from '@airiot/client'

// ECharts 图表类型定义
interface EChartSchema {
  key: string
  echartType: string
  roseType?: boolean
}

const echartSchema: EChartSchema[] = [
  { key: 'bar', echartType: 'bar' },
  { key: 'line', echartType: 'line' },
  { key: 'scatter', echartType: 'scatter' },
  { key: 'pie', echartType: 'pie', roseType: false }
]

// 图表统计数据接口
interface ChartStat {
  stacked?: boolean
  nCategories?: number
  nStacks?: number
  nValues?: number
  grouped?: boolean
}

// 图表字段接口
interface ChartField {
  name: string
  alias?: string
  alias_en?: string
  biType?: string
}

// 图表维度接口
interface ChartDimension {
  id?: string
  name: string
  alias?: string
  alias_en?: string
  timeFormat?: string
}

// 图表数据接口
interface ChartData {
  fields: ChartField[]
  data?: any[][]
  stat?: ChartStat
  style?: {
    dimension?: ChartDimension[]
    echartType?: string
    measure?: any[]
    baseValue?: {
      option?: any
    }
  }
}

// 递归，字符串转函数
const StrToFunction = (obj: any): any => {
  const result = _.cloneDeep(obj)
  for (const key in result) {
    if (_.has(result, key)) {
      if (_.isString(result[key]) && result[key].indexOf(' => ') > -1) {
        try {
          const func = new Function(`return ${result[key]}`)
          result[key] = func()
        } catch (e) {
          console.error(`字符串转函数失败: ${result[key]}`, e)
          result[key] = result[key]
        }
      } else if (_.isObject(result[key])) {
        result[key] = StrToFunction(result[key])
      }
    }
  }
  return result
}

// 内容国际化
const getAliasLang = async (item: ChartField | undefined) => {
  if (!item) return undefined
  const settings = await getSettings()
  const { language } = settings

  if (language && language !== 'zh_Hans') {
    const aliasKey = `alias_${language}` as keyof ChartField
    return (item[aliasKey] as string) || item.alias
  }
  return item.alias
}

// 格式化时间
const formatTime = (datas: any[], chart: ChartData): any[] => {
  if (_.isEmpty(datas)) return datas
  const fs = chart.fields || []
  const ds = chart.style?.dimension || []
  return datas.map((d, i) => {
    if (fs[i]?.biType === 'time' && ds[i]?.timeFormat) {
      return d ? dayjs(d).format(ds[i].timeFormat!) : d
    }
    return d
  })
}

// 获取堆叠柱状图配置
const getStackBarOption = (chart: ChartData): any => {
  if (!chart.stat?.stacked || !chart.fields) {
    return {}
  }
  const n = chart.stat.nCategories || 0
  const m = (chart.stat.nCategories || 0) + (chart.stat.nStacks || 0)

  const labels = new Set<string>()
  const stacks = new Set<string>()
  const source: any[][] = []
  const stackField = chart.fields[m - 1]
  const stack = stackField?.name || 'stack'
  const dimensions = [
    chart.fields[0]?.name,
    chart.fields[m]?.name,
    stack
  ].filter(Boolean)

  if (chart.data) {
    chart.data.forEach(data => {
      const key = formatTime(data.slice(0, n), chart).join('\n')
      labels.add(key)
      source.push([key, data[m], data[m - 1]])
      stacks.add(data[m - 1])
    })
  }

  const dataset: Array<{ dimensions?: string[]; source?: any[][]; sourceHeader?: boolean; transform?: any }> = [{ dimensions, source, sourceHeader: false }]

  const stackList = Array.from(stacks)
  for (let i = 0; i < stackList.length; i++) {
    dataset.push({
      transform: {
        type: 'filter',
        config: { dimension: stack, value: stackList[i] }
      }
    })
  }

  const series = stackList.map((label) => ({
    type: 'bar',
    stack: 'total',
    datasetIndex: label ? stackList.indexOf(label) + 1 : 1,
    name: label,
    emphasis: {
      focus: 'series'
    }
  }))

  return {
    dataset,
    xAxis: { type: 'category' },
    yAxis: { type: 'value' },
    series,
    legend: { type: 'scroll', right: 10 },
    tooltip: {
      trigger: 'item',
      axisPointer: {
        type: 'shadow'
      }
    },
    grid: {
      left: '3%',
      right: '4%',
      bottom: '3%',
      containLabel: true
    }
  }
}

// 获取通用图表配置
const getCommonOption = (chart: ChartData): any => {
  if (_.isEmpty(chart) || !chart.stat) {
    return undefined
  }
  const n = chart.stat.nCategories || 0
  const m = (chart.stat.nCategories || 0) + (chart.stat.nStacks || 0)
  const nValues = chart.stat.nValues || 0

  const current = chart?.style?.echartType
    ? echartSchema.find((val) => chart?.style?.echartType === val?.key)
    : { key: 'bar', echartType: 'bar' }

  const source: any[][] = []
  const isXValue = n === 0 && nValues > 1 && ['line', 'scatter'].includes(current?.echartType || '')
  const d1 = chart?.fields?.slice(0, n)?.map((f) => getAliasLang(f) || f?.name).join('\n')
  const d2 = chart.fields?.[n]?.name
  const dimensions = chart?.fields?.length
    ? isXValue
      ? [chart.fields[0]?.name, chart.fields[1]?.name]
      : [d1, d2]
    : []

  if (chart.data) {
    chart.data.forEach((data) => {
      const key = formatTime(data.slice(0, n), chart).join('\n')
      if (isXValue) {
        source.push([data[0], data[1]])
      } else {
        source.push([key, data[m]])
      }
    })
  }

  if (chart.stat?.grouped && current?.echartType === 'pie') {
    source.forEach((s) => {
      if (!_.isNaN(Number(s[nValues]))) {
        s[nValues] = Number(s[nValues])
      }
    })
  }

  const series = chart?.style?.measure?.length
    ? chart?.style?.measure.map(() => {
      if (current?.echartType === 'pie') {
        const pieOption: any = {
          name: d2,
          type: current?.echartType,
          center: ['50%', '50%'],
          itemStyle: { borderRadius: 5 },
          label: { show: false },
          emphasis: { label: { show: true } },
          data: source.map((s) => s[nValues])
        }
        if (current?.roseType) {
          return {
            ...pieOption,
            radius: [20, 140],
            roseType: 'radius'
          }
        }
        return pieOption
      }
      return { type: current?.echartType, data: source.map((s) => s[nValues]) }
    })
    : []

  const option: any = {
    dataset: [{ dimensions, source, sourceHeader: false }],
    grid: {},
    legend: {
      right: 10
    },
    tooltip: {
      show: true
    },
    series
  }

  if (isXValue) {
    option.xAxis = { type: 'value', data: source.map((s) => s[0]) }
    option.yAxis = { type: 'value' }
  } else if (current?.echartType !== 'pie') {
    option.xAxis = { type: 'category', data: source.map((s) => s[0]) }
    option.yAxis = {}
    option.dataZoom = {}
  }
  return option
}

// 获取图表配置
const getChartOption = (data: ChartData | null, echartOption: any): any => {
  if (!data) return echartOption
  const eOption = echartOption || data?.style?.baseValue?.option || {}
  const chartOption = data?.stat?.stacked ? getStackBarOption(data) : getCommonOption(data)
  return chartOption ? _.merge({}, chartOption, JSON.parse(JSON.stringify(eOption))) : eOption
}

export interface View {
  id: string
  name: string
  datasetId: string
}

export interface ChartEchartsProps extends Omit<BaseChartProps, 'option'> {
  view?: View
  echartOption?: any
  chartCode?: string
}

const ChartEcharts: React.FC<ChartEchartsProps> = (props) => {
  const { view, echartOption, chartCode } = props

  const [chartData, setChartData] = React.useState<ChartData | null>(null)

  React.useEffect(() => {
    if (view?.id) {
      const api = createAPI({
        resource: 'ds/view/preview',
        name: 'ds-view-preview'
      })
      api
        .fetch(`?id=${view.id}`, {
          method: 'POST',
          body: JSON.stringify(view)
        })
        .then(({ json }: { json: ChartData }) => {
          setChartData(json)
        })
        .catch((error) => {
          console.error('获取图表数据失败:', error)
        })
    }
  }, [view?.id])

  if (!view?.id) {
    return null
  }

  const chartOption = getChartOption(chartData, echartOption)

  return (
    <BaseChart option={StrToFunction(chartOption)} chartCode={chartCode} {...props} />
  )
}

ChartEcharts.displayName = 'ChartEcharts'

export default ChartEcharts

'use client'

import { ReactNode, useEffect, useMemo, useState, useRef, useCallback } from 'react'
import { useDatasetSet } from '@airiot/client'
import { ContextProvider } from '@/registry/components/container-context-provider/context-provider'

// ==================== Types ====================

export interface DatasourceApiProps {
  id?: string
  url?: string
  method?: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE'
  headers?: Array<{ name: string; value: string }>
  body?: Array<{ name: string; value: string }>
  predata?: boolean
  table?: any
  appkey?: string
  appsecret?: string
  interval?: number
  submit?: string
  children?: ReactNode
}

export interface ApiDataConfig {
  url?: string
  method?: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE'
  headers?: Array<{ name: string; value: string }>
  body?: Array<{ name: string; value: string }>
  predata?: boolean
  interval?: number
  table?: any
  appkey?: string
  appsecret?: string
  submit?: string
}

// 默认配置（包含示例数据用于调试）
export const defaultApiConfig: ApiDataConfig = {
  url: 'core/t/{table}/d',
  method: 'GET',
  headers: [],
  body: [],
  predata: false,
  interval: 0,
  table: {
    id: '子',
    title: '子表'
  },
  appkey: undefined,
  appsecret: undefined,
  submit: ''
}

// ==================== Utility Functions ====================

// 对象转 URL 参数
function objToUrlParams(obj: Record<string, any>, url: string): string {
  try {
    if (!url || typeof url !== 'string') {
      return ''
    }
    let params = ''
    for (const key in obj) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        if (Array.isArray(obj[key])) {
          let arrayParams = ''
          for (let i = 0; i < obj[key].length; i++) {
            arrayParams += `${key}=${obj[key][i].toString()}&`
          }
          params += arrayParams.slice(0, -1) // remove last "&"
        } else if (typeof obj[key] === 'object' && obj[key] !== null) {
          const nestedParams = objToUrlParams(obj[key], url)
          params += `${key}=${nestedParams}&`
        } else {
          params += `${key}=${obj[key].toString()}&`
        }
      }
    }
    params = params.slice(0, -1) // remove last "&"
    const separator = url.includes('?') ? '&' : '?'
    return url + separator + params
  } catch {
    return ''
  }
}

// 数组转键值对
function arrayToKv(arr: Array<{ name: string; value: any }>): Record<string, any> {
  const kv: Record<string, any> = {}
  if (arr?.length) {
    arr.forEach(item => {
      if (item && !isEmpty(item)) {
        kv[item.name] = item.value
      }
    })
  }
  return kv
}

function isEmpty(obj: any): boolean {
  if (obj == null) return true
  if (Array.isArray(obj)) return obj.length === 0
  if (typeof obj === 'object') return Object.keys(obj).length === 0
  return false
}

// 检查是否是 HTTP(S) URL
function checkHttp(url: string): boolean {
  if (!url) return false
  const regex = /^(https?:\/\/)/i
  return regex.test(url)
}

// 过滤结果为图表格式
function filterResult(json: any): { dimensions: any[]; source: any[] } {
  let _json = json
  let dimensions: any[] = []
  let source: any[] = []

  try {
    if (typeof _json === 'object' && !Array.isArray(_json)) {
      _json = [_json]
    } else if (!Array.isArray(_json)) {
      _json = [{ result: _json }]
    }

    _json.forEach((item: any) => {
      const keys = Object.keys(item)
      dimensions = [...new Set([...dimensions, ...keys])]
    })

    _json.forEach((item: any) => {
      const values: any[] = []
      dimensions.forEach(key => {
        values.push(item[key])
      })
      source.push(values)
    })
  } catch (err) {
    console.warn('过滤数据失败:', err)
  }

  return { dimensions, source }
}

// ==================== Hook ====================

// API 数据 Hook
function useApiData(config: ApiDataConfig) {
  const {
    url = '',
    method = 'GET',
    headers = [],
    body = [],
    predata = false,
    interval = 0,
    table,
    appkey,
    appsecret,
    submit = '',
  } = config

  const [dataset, setDataset] = useState<any>(null)
  const [loading, setLoading] = useState(false)
  const [requestId, setRequestId] = useState<string | null>(null)
  const queryCallback = useRef<(() => void) | null>(null)

  // 过滤数据
  const filterData = useCallback((data: any) => {
    if (predata) {
      return filterResult(data)
    }
    return data
  }, [predata])

  // 获取数据
  const fetchData = useCallback(async () => {
    if (!url) {
      console.warn('URL 为空，无法获取数据')
      return
    }

    setLoading(true)

    try {
      let responseData: any

      // 判断 URL 类型
      const isHttpUrl = checkHttp(url)
      const hasTablePlaceholder = url.includes('{table}')
      const hasAuthPlaceholder = url.includes('{appkey}') || url.includes('{appsecret}')

      if (isHttpUrl) {
        // 情况 4: HTTP(S) 外部接口 - 无需其他参数
        const requestOptions: RequestInit = {
          method,
          headers: {
            'Content-Type': 'application/json',
            ...arrayToKv(headers)
          }
        }

        if (method !== 'GET' && body.length > 0) {
          requestOptions.body = JSON.stringify(arrayToKv(body))
        }

        const requestUrl = method === 'GET' && body.length > 0
          ? objToUrlParams(arrayToKv(body), url)
          : url

        const response = await fetch(requestUrl, requestOptions)
        responseData = await response.json()
      } else {
        // 内部 API 调用 (使用 @airiot/client)
        const { api } = await import('@airiot/client')

        let path = url

        // 情况 1: 包含 {table} 占位符 - 需要配置 table 参数
        if (hasTablePlaceholder) {
          if (!table?.id) {
            console.warn('URL 包含 {table} 占位符，但未配置 table 参数')
            setLoading(false)
            return
          }
          path = url.replace('{table}', table.id)
        }

        // 情况 3: 包含认证占位符 - 需要配置 appkey 和 appsecret
        if (hasAuthPlaceholder) {
          if (!appkey || !appsecret) {
            console.warn('URL 包含 {appkey} 或 {appsecret} 占位符，但未完整配置认证参数')
            setLoading(false)
            return
          }
          path = url
            .replace('{appkey}', appkey)
            .replace('{appsecret}', appsecret)
        }

        // 情况 2: 普通内部路径 (如 'core/systemVariable') - 无需其他参数
        // 直接使用原始 URL

        // 添加查询参数（GET 请求）
        if (method === 'GET' && body.length > 0) {
          path = objToUrlParams(arrayToKv(body), path)
        }

        // 使用 @airiot/client 的 API
        const bodyStr = method !== 'GET' && body.length > 0 ? JSON.stringify(arrayToKv(body)) : undefined

        const apiRet = api({
          name: path,
        })

        const response = await apiRet.fetch('', {
          method,
          headers: arrayToKv(headers),
          body: bodyStr,
        })
        responseData = response.json
      }

      // 处理数据
      const processedData = filterData(responseData)
      setDataset(processedData)
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 11)}`)
    } catch (error) {
      console.error('获取数据失败:', error)
      setDataset(null)
    } finally {
      setLoading(false)
    }
  }, [url, method, headers, body, predata, table, appkey, appsecret, filterData])

  // 保存到 ref
  queryCallback.current = fetchData

  // 初始加载
  useEffect(() => {
    queryCallback.current?.()
  }, [])

  // submit 变化时触发查询
  useEffect(() => {
    if (submit) {
      queryCallback.current?.()
    }
  }, [submit])

  // 自动轮询
  useEffect(() => {
    if (!interval || interval <= 0) return

    const tick = () => {
      queryCallback.current?.()
    }

    const id = setInterval(tick, interval * 1000)
    return () => clearInterval(id)
  }, [interval])

  return { dataset, loading, requestId, fetchData }
}

