    table: {
      id: 'A',
      name: 'A',
      tableMajorType: 'device'
    },
    tableData: {
      id: 'A001',
      name: 'A001',
      table: {
        id: 'A',
        name: 'A',
        tableMajorType: 'device'
      }
    },
