// ==================== Constants ====================

const ACCUMULATOR_LABELS: Record<string, string> = {
  '$count': '个数',
  '$avg': '平均值',
  '$first': '首位值',
  '$last': '末尾值',
  '$max': '最大值',
  '$min': '最小值',
  '$sum': '总和'
}

const INNER_FIELDS = [
  '_department',
  '_departmentInfo',
  '_deptTableAndField',
  '_parent',
  'deletePermission',
  'editPermission'
]

const SPECIAL_RESOURCE_IDS: Record<string, string> = {
  '_#$airiot_log': 'core/log',
  '_#$airiot_warning': 'warning/warning'
}

// ==================== Utility Functions ====================

const fetchSchema = async ({ id, selectType }: { id?: string; selectType?: string }): Promise<Schema | null> => {
  if (!id) return null

  try {
    if (selectType === 'dataset') {
      const { json } = await api({ name: `ds/dataset/jst/schema/${id}` }).fetch('')
      const schema = _.cloneDeep(json?.schema || {})

      for (const key of _.keys(schema.properties)) {
        const item = schema.properties[key]
        if (item?.tableName) {
          item.title = `${item.title}(${item.tableName})`
        }
      }

      return schema
    } else {
      if (id in SPECIAL_RESOURCE_IDS) {
        return null
      }

      const { json } = await api({ name: `core/t/schema/${id}` }).fetch('')
      return json?.schema || {}
    }
  } catch (error) {
    console.error('获取 Schema 失败:', error)
    return null
  }
}

const dealExtraSchema = async (
  list: any[],
  extraSchema: any,
  table: TableDataConfig['table']
): Promise<any[]> => {
  if (!list?.length || !extraSchema || !table?.key) {
    return list
  }

  try {
    const { json } = await api({ name: `core/t/schema/${table.key}` }).fetch('')
    const tableSchemaProperties = json?.schema?.properties

    if (!tableSchemaProperties) {
      return list
    }

    return list.map(item => {
      const res: Record<string, any> = {}

      Object.keys(item).forEach(key => {
        res[key] = item[key]

        if (tableSchemaProperties[key]?.config === '选择器') {
          const num = tableSchemaProperties[key].enum1?.indexOf(item[key])
          const label = tableSchemaProperties[key].enum_title1?.[num]
          if (label !== undefined) {
            res[key + '-label'] = label
          }
        }
      })

      return res
    })
  } catch (error) {
    console.error('处理额外 Schema 失败:', error)
    return list
  }
}

const makeDateOperation = ({ dateOperator, field }: GroupItemConfig): any => {
  const fieldId = _.isObject(field) ? (field as FieldConfig).id : field
  if (!fieldId) return null

  const $field = '$' + fieldId

  switch (dateOperator) {
    case '天':
      return { $dateToString: { format: '%Y-%m-%d', date: $field } }
    case '周':
      return { $dateToString: { format: '%Y-%V', date: $field } }
    case '月':
      return { $dateToString: { format: '%Y-%m', date: $field } }
    case '年':
      return { $year: $field }
    case '一小时内的分钟数':
      return { $minute: $field }
    case '一天内的小时数':
      return { $hour: $field }
    case '一周内的天数':
      return { $dayOfWeek: $field }
    case '一月内的天数':
      return { $dayOfMonth: $field }
    case '一年内的天数':
      return { $dayOfYear: $field }
    case '一年内的星期数':
      return { $week: $field }
    case '一年内的月数':
      return { $month: $field }
    default:
      return $field
  }
}

const buildQuery = (
  group: GroupItemConfig[] = [],
  columns: ColumnItemConfig[] = [],
  schema: Schema | null
): { groupBy: Record<string, any>; groupFields: Record<string, any> } => {
  const groupBy: Record<string, any> = {}
  const groupFields: Record<string, any> = {}

  group.forEach(g => {
    if (!g.field) return

    const field = _.isPlainObject(g.field)
      ? (g.field as FieldConfig).type === 'tag'
        ? 'param-' + (g.field as FieldConfig).id
        : (g.field as FieldConfig).id || (g.field as FieldConfig).key
      : g.field

    if (!field) return

    let key = field
    const properties = schema?.properties || {}

    if (key && typeof key === 'string' && key.indexOf('.') > 0) {
      key = key.split('.').join('.properties.')
    }

    const fieldTitle = _.get(properties, `${field}.title`)
    const name = field === 'fields.id' ? '数据点标识' : (typeof fieldTitle === 'string' ? fieldTitle : fieldTitle?.title) || '未命名'

    if (g.dateOperator) {
      groupBy[String(name)] = makeDateOperation(g)
    } else {
      const $key = '$' + (key === 'tableDataId' ? 'tableData' : key)
      groupBy[String(name)] = $key
    }
  })

  columns.forEach(column => {
    const name = column.name || ACCUMULATOR_LABELS[column.accumulator || '']

    if (!column.accumulator) return

    if (column.accumulator === '$count') {
      groupFields[String(name)] = { $sum: 1 }
    } else if (column.field || column.expression) {
      const field = _.isPlainObject(column.field)
        ? (column.field as FieldConfig).type === 'tag'
          ? 'param-' + (column.field as FieldConfig).id
          : (column.field as FieldConfig).id
        : column.field

      const $field = field ? '$' + field : column.expression
      groupFields[String(name)] = { [column.accumulator]: $field }
    }
  })

  return { groupBy, groupFields }
}

const sortObjectsByKeyOrder = (
  arrayOfObjects: Record<string, any>[],
  keyOrder: string[]
): Record<string, any>[] => {
  return arrayOfObjects.map(obj => {
    const entries = Object.entries(obj)

    entries.sort(([keyA], [keyB]) => {
      const indexA = keyOrder.indexOf(keyA)
      const indexB = keyOrder.indexOf(keyB)

      if (indexA !== -1 && indexB !== -1) {
        return indexA - indexB
      } else if (indexA !== -1) {
        return -1
      } else if (indexB !== -1) {
        return 1
      }
      return 0
    })

    return Object.fromEntries(entries)
  })
}

const getColumnFieldMapping = (columns: ColumnItemConfig[] = []): Map<string, string> => {
  const mapping = new Map<string, string>()

  columns.forEach(column => {
    const displayName = column.name || ACCUMULATOR_LABELS[column.accumulator || '']
    if (displayName && column.field && typeof column.field !== 'string' && column.field.id) {
      mapping.set(displayName, column.field.id)
    }
  })

  return mapping
}

const isInnerField = (key: string): boolean => {
  return INNER_FIELDS.includes(key)
}

// ==================== Main Hook ====================

function useTableData(config: TableDataConfig) {
  const {
    selectType = 'table',
    table,
    initFilter = {},
    isGroup = false,
    queryFields = [],
    projectAll = false,
    fieldOrder = [],
    group = [],
    columns = [],
    statsBySingle = null,
    limit = 1000,
    skip = 0,
    interval = 0,
    showInnerField = false,
    feildFormat = [],
    extraSchema,
    submit,
  } = config

  const [schema, setSchema] = useState<Schema | null>(null)
  const [dataset, setDataset] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [requestId, setRequestId] = useState<string | null>(null)

  const queryCallback = useRef<(() => void) | null>(null)
  const lastSubmitRef = useRef<string | undefined>(undefined)
  const hasInitializedRef = useRef(false)

  const configRef = useRef({
    table,
    selectType,
    schema,
    initFilter,
    isGroup,
    queryFields,
    projectAll,
    fieldOrder,
    group,
    columns,
    statsBySingle,
    limit,
    skip,
    feildFormat,
    extraSchema,
    showInnerField
  })

  useEffect(() => {
    configRef.current = {
      table,
      selectType,
      schema,
      initFilter,
      isGroup,
      queryFields,
      projectAll,
      fieldOrder,
      group,
      columns,
      statsBySingle,
      limit,
      skip,
      feildFormat,
      extraSchema,
      showInnerField
    }
  })

  const fieldTransform = useMemo(() => {
    const transforms: Record<string, (value: any) => any> = {}

    if (Array.isArray(group)) {
      group.forEach(g => {
        const key = _.isString(g?.field) ? g.field : g?.field?.id
        if (!key) return

        let normalizedKey = key
        if (normalizedKey.indexOf('.') > 0) {
          normalizedKey = normalizedKey.split('.').join('.properties.')
        }

        const field = _.get(schema?.properties, normalizedKey)
        if (field?.transform && _.isFunction(field.transform)) {
          transforms[field.title || ''] = field.transform
        }
      })
    }

    return transforms
  }, [schema, group])

  const queryData = useCallback(async () => {
    const {
      table,
      selectType,
      schema,
      initFilter,
      isGroup,
      queryFields,
      projectAll,
      fieldOrder,
      group,
      columns,
      statsBySingle,
      limit,
      skip,
      feildFormat,
      extraSchema,
      showInnerField
    } = configRef.current

    const tableId = table?.value || table?.id
    if (!tableId || !schema) {
      return
    }

    try {
      setLoading(true)

      let resource = `core/t/${tableId}/d`

      if (selectType === 'dataset') {
        resource = `ds/dataset/jst/data/${tableId}`
      } else if (tableId in SPECIAL_RESOURCE_IDS) {
        resource = SPECIAL_RESOURCE_IDS[tableId]
      }

      const query: any = {
        filter: initFilter
      }

      let groupKeys: string[] = []

      if (isGroup || _.isUndefined(isGroup)) {
        const { groupBy, groupFields } = buildQuery(group, columns, schema)
        groupKeys = _.keys(groupBy)

        if (_.isEmpty(groupFields)) {
          setDataset([])
          return
        }

        query.groupBy = groupBy
        query.groupFields = groupFields
      } else {
        if (projectAll) {
          query.projectAll = true
        } else if (queryFields.length > 0) {
          query.project = {}
          queryFields.forEach(field => {
            query.project[field] = 1
          })
        }

        if (fieldOrder.length > 0) {
          query.sorts = fieldOrder.map(order => ({
            [order.value]: order?.order === 'ASC' ? 1 : -1
          }))
        }
      }

      query.limit = limit || 1000
      if (skip) {
        query.skip = skip
      }

      if (!_.isNull(statsBySingle)) {
        query.statsBySingle = statsBySingle
      }

      const queryString = encodeURIComponent(JSON.stringify(query))
      const { json } = await api({ name: resource }).fetch(`?query=${queryString}`)

      const resultList = await dealExtraSchema(json || [], extraSchema, table)

      const columnFieldMapping = getColumnFieldMapping(columns)

      const sortedData = groupKeys.length > 0
        ? sortObjectsByKeyOrder(resultList, groupKeys)
        : resultList

      const transformedData = sortedData.map(item => {
        const transformedItem: Record<string, any> = {}

        Object.entries(item).forEach(([k, v]) => {
          const mappedFieldId = columnFieldMapping.get(k)
          const actualKey = mappedFieldId || k

          if (isInnerField(actualKey) && !showInnerField) {
            return
          }

          if (fieldTransform[k]) {
            transformedItem[k] = fieldTransform[k](v)
          } else {
            let formatted = false

            for (const fieldFormat of feildFormat || []) {
              const fieldId = fieldFormat?.field?.id || fieldFormat?.field?.key
              const fieldTitle = fieldFormat?.field?.title

              if (fieldId === actualKey || fieldTitle === actualKey) {
                const fieldType = fieldFormat?.field?.propertyType || fieldFormat?.field?.type
                const formatValue = typeof fieldFormat?.format === 'string'
                  ? fieldFormat.format
                  : fieldFormat?.format?.format || ''

                if (fieldType === 'string') {
                  transformedItem[k] = dateFormat(formatValue, v)
                } else {
                  transformedItem[k] = numberFormat(formatValue, v)
                }

                formatted = true
                break
              }
            }

            if (!formatted) {
              transformedItem[k] = v
            }
          }
        })

        return transformedItem
      })

      setDataset(transformedData)
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 9)}`)
    } catch (error) {
      console.error('查询表数据失败:', error)
      toast.error('数据查询出现错误，请检查数据')
      setDataset([])
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 9)}`)
    } finally {
      setLoading(false)
    }
  }, [])

  queryCallback.current = queryData

  useEffect(() => {
    const tableId = table?.value || table?.id
    if (!tableId) {
      return
    }

    hasInitializedRef.current = false
    lastSubmitRef.current = undefined

    fetchSchema({ id: tableId, selectType })
      .then(setSchema)
      .catch(err => {
        console.error('获取 Schema 失败:', err)
        setSchema(null)
      })
  }, [table?.value, table?.id, selectType, table])

  useEffect(() => {
    const tableId = table?.value || table?.id

    if (!tableId || !schema?.name) {
      return
    }

    if (hasInitializedRef.current && lastSubmitRef.current === submit) {
      return
    }

    hasInitializedRef.current = true
    lastSubmitRef.current = submit

    queryData()
  }, [submit, schema?.name])

  useEffect(() => {
    if (!interval || interval <= 0) {
      return
    }

    const tick = () => {
      queryCallback.current?.()
    }

    const id = setInterval(tick, interval * 1000)
    return () => clearInterval(id)
  }, [interval])

  return {
    dataset,
    loading,
    requestId
  }
}

export function DatasourceTable({
  id = 'datasource-table',
  selectType = 'table',
  table,
  initFilter,
  isGroup = false,
  showInnerField = false,
  statsBySingle,
  feildFormat,
  queryFields,
  interval = 0,
  submit,
  children
}: DatasourceTableProps) {
  const datasetSet = useDatasetSet(id)

  const { dataset, loading, requestId } = useTableData({
    selectType,
    table,
    initFilter,
    isGroup,
    showInnerField,
    statsBySingle,
    feildFormat,
    queryFields,
    interval,
    submit
  })

  useEffect(() => {
    datasetSet({ data: dataset, loading })
  }, [requestId, loading, datasetSet])

  const contextData = useMemo(() => {
    return [{
      data: dataset,
      loading
    }]
  }, [requestId, loading])

  return (
    <ContextProvider data={contextData}>
      {children}
    </ContextProvider>
  )
}

import _ from 'lodash'
import dayjs from 'dayjs'

/**
 * 生成时间查询条件
 * @param timeRange 时间范围配置
 * @returns 查询条件数组或 null
 */
export const timeQuery = (timeRange: any) => {
  const { type, count, unit, fromNow, time, range, historyTime } = timeRange
  const start = historyTime ? dayjs(historyTime) : dayjs()
  const end = historyTime ? dayjs(historyTime) : dayjs()

  if (type == 'forward' && count && unit) {
    if (!fromNow) {
      return [
        `time >= '${start.startOf(unit).subtract(count, unit).toISOString()}'`,
        `time < '${end.startOf(unit).toISOString()}'`
      ]
    } else {
      return [
        `time >= '${start.subtract(count, unit).toISOString()}'`,
        `time < '${end.toISOString()}'`
      ]
    }
  }

  if (type == 'backward' && count && unit) {
    if (!fromNow) {
      return [
        `time < '${start.endOf(unit).add(count, unit).toISOString()}'`,
        `time > '${end.endOf(unit).toISOString()}'`
      ]
    } else {
      return [
        `time < '${start.add(count, unit).toISOString()}'`,
        `time > '${end.toISOString()}'`
      ]
    }
  }

  if (type == 'now' && unit) {
    return [`time > '${start.startOf(unit).toISOString()}'`, `time <= '${end.toISOString()}'`]
  }

  if (type == 'before' && time) {
    return [`time < '${dayjs(time).toISOString()}'`]
  }

  if (type == 'after' && time) {
    return [`time >= '${dayjs(time).toISOString()}'`]
  }

  if (type == 'between' && range && range.lte && range.gte) {
    return [
      `time >= '${dayjs(range.gte).toISOString()}'`,
      `time <= '${dayjs(range.lte).toISOString()}'`
    ]
  } else if (type === 'between' && range && range.financialMonth) {
    // 处理财务月时间范围
    const { financialMonth } = range
    const { date: financialDate, time: financialTime } = range.financialMonth || {}

    if (financialMonth && financialDate && financialTime) {
      // 解析财务月，格式如 "2025-02"
      const [year, month] = financialMonth.split('-').map(Number)

      // 计算财务月开始时间：当前月的指定日期和时间
      const startTime = dayjs()
        .year(year)
        .month(month - 1) // dayjs的月份从0开始
        .date(financialDate)
        .startOf('day')
        .add(dayjs.duration(financialTime))

      // 计算财务月结束时间：下个月的指定日期和时间减1秒
      const endTime = dayjs(startTime)
        .add(1, 'month')
        .subtract(1, 'second')

      return [
        `time >= '${startTime.toISOString()}'`,
        `time <= '${endTime.toISOString()}'`
      ]
    }
  }

  return null
}

/**
 * 数字格式化
 */
export const numberFormat = (format: string, value: any): any => {
  const num = Number(value)
  if (isNaN(num)) {
    return null
  }

  let result: any = num
  const regex = /^[0-9]$/

  if (format && !regex.test(format)) {
    // 预定义格式
    switch (format) {
      case 'percent':
        result = _.isNumber(result) ? (_.round(result * 100) + '%') : (result || 'n/a')
        break
      case 'percentPoint':
        result = _.isNumber(result) ? (_.round(result * 100, 2) + '%') : (result || 'n/a')
        break
      case 'thousandth':
        result = _.isNumber(result) ? _.round(result).toLocaleString() : (result || 'n/a')
        break
      case 'thousandthPoint':
        result = _.isNumber(result) ? _.round(result, 2).toLocaleString() : (result || 'n/a')
        break
      default:
        break
    }
  } else {
    // 保留 X 位小数
    result = result.toFixed(parseInt(format) || 0)
  }

  if (_.isNaN(result) || result === 'NaN') {
    result = null
  }

  return result
}

/**
 * 日期格式化
 */
export const dateFormat = (format: string, value: any): any => {
  if (!value) {
    return null
  }

  const t = dayjs(value)
  let time: any = t

  switch (format) {
    case '秒级时间戳':
      time = t.unix().toString()
      break
    case '毫秒级时间戳':
      time = t.valueOf().toString()
      break
    case '历史数据时间':
      time = t.toISOString()
      break
    default:
      time = t.format(format)
      break
  }

  if (time === 'Invalid Date') {
    time = null
  }

  return time
}

/**
 * 数据源类型定义
 * 统一历史数据和实时数据的数据点结构
 *
 * 数据层级关系：
 * Table (表) -> TableData (表数据/设备) -> Tag (标签/数据点)
 */

// ==================== 基础数据类型 ====================

/**
 * 表信息（Table）
 * 定义一个表的基本信息
 * @example
 * { id: 'A', name: '设备表' }
 */
export interface TableInfo {
  id: string
  name?: string
  title?: string
  tableMajorType?: string  // 表类型，如 'device'
  [key: string]: any
}

/**
 * 表数据信息（TableData）
 * 表中的某条记录，如某个设备
 * @example
 * {
 *   id: 'A001',
 *   name: '1号设备',
 *   table: { id: 'A', name: '设备表' }
 * }
 */
export interface TableDataInfo {
  id: string
  name?: string
  title?: string
  table: TableInfo
  tabledata?: string  // 表数据ID（向后兼容）
  [key: string]: any
}

/**
 * 标签信息（Tag）
 * 表数据上的某个数据点/字段
 * @example
 * { id: 'temperature', name: '温度' }
 * @example with tableData
 * { id: 'temperature', name: '温度', tableData: { id: 'A001', table: { id: 'A' } } }
 */
export interface TagInfo {
  id: string
  name?: string
  tableData?: TableDataInfo
}

// ==================== 标签配置类型 ====================

/**
 * 标签值（TagValue）
 * 标签的唯一标识符，用于快速定位
 * @example
 * {
 *   tableId: 'A',
 *   tableDataId: 'A001',
 *   tagId: 'temperature'
 * }
 */
export interface TagValue {
  tableId: string
  tableDataId: string
  tagId: string
}

/**
 * 标签配置（TagConfig）
 * 完整的数据点配置，包含表、表数据、标签的完整信息
 *
 * 支持两种输入格式：
 * 1. 直接格式（推荐）：直接提供 table、tableData、tag 对象
 * 2. 简写格式：使用 tableDataTag.value 提供标签值
 *
 * @example 直接格式
 * {
 *   table: { id: 'A', name: '设备表' },
 *   tableData: { id: 'A001', name: '1号设备', table: { id: 'A' } },
 *   tag: { id: 'temperature', name: '温度' },
 *   title: '1号设备温度',
 *   fixed: 2
 * }
 *
 * @example 简写格式
 * {
 *   tableDataTag: {
 *     value: { tableId: 'A', tableDataId: 'A001', tagId: 'temperature' },
 *     name: '1号设备温度'
 *   }
 * }
 */
export interface TagConfig {
  // ==================== 方式1：直接格式（推荐） ====================

  /**
   * 表信息
   */
  table?: TableInfo

  /**
   * 表数据信息（设备等）
   */
  tableData?: TableDataInfo

  /**
   * 标签信息（数据点）
   */
  tag?: TagInfo

  // ==================== 方式2：tableDataTag 简写格式（向后兼容） ====================

  /**
   * tableDataTag 配置格式
   * value: 标签的唯一标识符
   * name: 显示名称
   */
  tableDataTag?: {
    value?: TagValue
    name?: string
  }

  // ==================== 通用配置属性 ====================

  /**
   * 数据点标题/显示名称
   * 优先级最高，用于图表显示
   */
  title?: string

  /**
   * 数据点名称
   */
  name?: string

  /**
   * 唯一键，用于数据标识
   */
  key?: string

  /**
   * 唯一标识符（向后兼容）
   */
  uid?: string
  id?: string

  /**
   * 表ID字符串（简写，向后兼容）
   */
  tableId?: string

  /**
   * 分组相关
   */
  group?: string
  groupType?: 'id' | 'department' | 'other'

  /**
   * 数据格式化
   */
  fixed?: number  // 保留小数位数
  func?: string   // 聚合函数

  /**
   * 查询相关
   */
  fields?: string[]
  query?: Array<Array<{ field?: string; method?: string }>>

  /**
   * 其他扩展属性
   */
  [key: string]: any
}

/**
 * 数据点配置（TagConfig 的别名）
 */
export type DataPointConfig = TagConfig
export type DataItemConfig = TagConfig

/**
 * 列配置
 */
