      props.onChange(value)
    }
  }

  const onValueChange = (value: any) => {
    if (like) {
      props.onChange({ like: value })
    } else {
      props.onChange(value)
    }
  }

  const onLikeChange = (like: boolean) => {
    if (like) {
      props.onChange({ like: value })
