    sourcePosition,
    targetPosition,
    pathType,
    markerEnd
  } = props

  const pathParams = {
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  }

  const sY = sourceY - 30
  const sx = sourceX - 240
  const tY = targetY + 60
  const p4 = {
    ...pathParams,
    sourceX: sourceX - 50,
    sourceY: sY,
    targetX: sx,
    targetY: sY,
  }
  const p5 = {
    ...pathParams,
    sourceX: sx,
    sourceY: sY,
    targetX: sx,
    targetY: tY,
  }
  const p6 = {
    ...pathParams,
    sourceX: sx,
    sourceY: tY,
    targetX: targetX - 105,
    targetY: tY,
  }

  const edgePath4 = pathType == 'smoothStep' ? getSmoothStepPath(p4) : getBezierPath(p4)
  const edgePath5 = pathType == 'smoothStep' ? getSmoothStepPath(p5) : getBezierPath(p5)
  const edgePath6 = pathType == 'smoothStep' ? getSmoothStepPath(p6) : getBezierPath(p6)

