      form?: {
        change: (field: string, value: any) => void
      }
    }
  }
  meta?: any
  record?: any
  antdForm?: any
  label?: string
  disabled?: boolean
  value?: {
    key: string
    label: string
    item?: any
  } | null | {
    key: string
    label: string
    item?: any
  }[]
  mode?: 'multiple' | 'tags'
  isOptionSelected?: (option: RelateFieldOption) => boolean
  style?: React.CSSProperties
  onChange?: (value: any) => void
}

/**
 * AsyncSelect - 异步选择器组件
 * 支持搜索、分页加载、精确搜索
 */
const AsyncSelect: React.FC<AsyncSelectProps> = (props) => {
  const {
    field = {},
    label = '请选择',
    disabled = false,
    mode,
    value: propValue,
    onChange,
    style,
  } = props

  const { displayField = 'name', schema, relateShowFields } = field

  // 状态管理
  const [loading, setLoading] = React.useState(false)
  const [pageLoading, setPageLoading] = React.useState(false)
  const [allOptions, setAllOptions] = React.useState<RelateFieldOption[]>([])
  const [filteredOptions, setFilteredOptions] = React.useState<RelateFieldOption[]>([])
  const [page, setPage] = React.useState(0)
  const [hasMore, setHasMore] = React.useState(true)
  const [open, setOpen] = React.useState(false)
  const [inputSearchValue, setInputSearchValue] = React.useState('')
  const [highlightedIndex, setHighlightedIndex] = React.useState(-1)

  const itemsRef = React.useRef<RelateFieldOption[]>([])
  const currentPageRef = React.useRef(0)
  const searchInputRef = React.useRef<HTMLInputElement>(null)
  const dropdownRef = React.useRef<HTMLDivElement>(null)

  const form = useFormContext()
  const outTable = React.useContext(Table2Context)

  const getFormState = () => {
    if (form) {
      return form.getValues()
    }
  }

  // 获取选项数据（不根据搜索词过滤，加载所有数据）
  const loadOptions = React.useCallback(
    async (pageNum: number = 0): Promise<number> => {
      if (currentPageRef.current >= pageNum && pageNum !== 0) {
        return 0
      }
      if (pageNum === 0) {
        itemsRef.current = []
        currentPageRef.current = 0
        setAllOptions([])
      }
      currentPageRef.current = pageNum

      let filterObj: any = {}
      dealFilter(filterObj, field, getFormState, outTable)

      setLoading(true)
      try {
        const s = schema || field.schema
        const resource = s?.name ? s?.name : `core/t/${s?.relate?.id}/d`

        // 创建 API 实例
        const api = createAPI({ resource })

        // 使用 api.query 查询数据
        const relateFieldKeys = relateShowFields?.map((f: { key: string }) => f.key) || []
        const { items } = await api.query(
          {
            limit: 100,
            skip: pageNum * 100,
            fields: ['id', displayField, ...relateFieldKeys].filter(Boolean)
          },
          filterObj
        )

        const newOptions = items.map((item: any) => ({
          value: item.id,
          label: item[displayField] || item.name || item.id,
          key: item.id,
          item,
        }))

        itemsRef.current = [...itemsRef.current, ...newOptions]

        setAllOptions((prev) => {
          // 使用 Map 去重（按 value/id 去重）
          const optionMap = new Map<string, RelateFieldOption>()
          // 先添加已有的选项
          prev.forEach((opt: RelateFieldOption) => optionMap.set(opt.value, opt))
          // 再添加新选项（会覆盖重复的）
          newOptions.forEach((opt: RelateFieldOption) => optionMap.set(opt.value, opt))
          return Array.from(optionMap.values())
        })
        setHasMore(items.length === 100)

        return items.length || 0
      } catch (error) {
        console.error('加载选项失败:', error)
        return 0
      } finally {
        setLoading(false)
      }
    },
    [JSON.stringify(field), displayField, schema, relateShowFields]
  )

  // 前端过滤选项
  React.useEffect(() => {
    if (!inputSearchValue) {
      setFilteredOptions(allOptions)
    } else {
      const searchLower = inputSearchValue.toLowerCase()
      const filtered = allOptions.filter((option) =>
        option.label?.toLowerCase().includes(searchLower)
      )
      setFilteredOptions(filtered)
    }
    setHighlightedIndex(-1)
  }, [inputSearchValue, allOptions])

  // 初始加载
  React.useEffect(() => {
    loadOptions()
  }, [loadOptions])

  // 多字段联动表单其他字段
  React.useEffect(() => {
    relateShowFields?.forEach((rsf) => {
      if (rsf.mapToCurrent && rsf.mapField) {
        const itemValue = isArray(propValue) ? propValue[0]?.item?.[rsf.key] : (propValue as any)?.item?.[rsf.key]
        if (itemValue) {
          field?.option?.form?.change(rsf.mapField, itemValue)
        }
      }
    })
  }, [JSON.stringify(propValue || {}), relateShowFields, field])

  // 处理选项选择
  const handleSelectOption = (option: RelateFieldOption) => {
    if (mode === 'multiple' && isArray(propValue)) {
      const isSelected = propValue.some((v: any) => v?.key === option.value)
      let newSelected: RelateFieldOption[]
      if (isSelected) {
        newSelected = propValue.filter((v: any) => v?.key !== option.value)
      } else {
        newSelected = [...propValue, option]
      }
      onChange?.(newSelected)
    } else {
      onChange?.(option)
      setOpen(false)
      setInputSearchValue('')
    }
  }

  // 处理清除
  const handleClear = (e: React.MouseEvent<SVGSVGElement>) => {
    e.stopPropagation()
    onChange?.(mode === 'multiple' ? [] : {})
    setInputSearchValue('')
  }

  // 处理键盘事件
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setHighlightedIndex((prev: number) => {
        const next = prev + 1
        return next < filteredOptions.length ? next : prev
      })
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setHighlightedIndex((prev: number) => {
        const next = prev - 1
        return next >= 0 ? next : 0
      })
    } else if (e.key === 'Enter') {
      e.preventDefault()
      if (highlightedIndex >= 0 && highlightedIndex < filteredOptions.length) {
        handleSelectOption(filteredOptions[highlightedIndex])
      }
    } else if (e.key === 'Escape') {
      setOpen(false)
    }
  }

  // 加载更多
  const loadMore = React.useCallback(async () => {
    if (pageLoading || !hasMore) return

    const nextPage = page + 1
    setPage(nextPage)
    setPageLoading(true)

    await loadOptions(nextPage)
    setPageLoading(false)
  }, [page, pageLoading, hasMore, loadOptions])

  // 格式化显示值
  const formatDisplayValue = (val: any): string => {
    if (!val) return ''
    if (typeof val === 'string') return val
    if (isObject(val) && (val as any).label) return (val as any).label
    return String(val)
  }

  const currentValue: any =
    mode === 'multiple'
      ? (isArray(propValue) ? propValue.map((v) => (v as any)?.key || v).filter(Boolean) : [])
      : (propValue as any)?.key || ''

  return (
    <div style={{ position: 'relative', width: '100%', minWidth: 150, ...style }}>
      <Popover open={open} onOpenChange={(newOpen: boolean) => {
        setOpen(newOpen)
        if (newOpen) {
          setTimeout(() => searchInputRef.current?.focus(), 0)
        } else {
          setInputSearchValue('')
        }
      }}>
        <PopoverTrigger asChild>
          <div
            className={cn(
              'flex items-center justify-between w-full h-10 px-3 py-2 text-sm bg-background border border-input rounded-md cursor-pointer hover:bg-accent hover:text-accent-foreground',
              disabled && 'cursor-not-allowed opacity-50'
            )}
            onClick={() => !disabled && setOpen(true)}
          >
            <span className={cn('flex-1 truncate', !propValue && 'text-muted-foreground')}>
              {mode === 'multiple' && isArray(propValue) && propValue.length > 0
                ? propValue.map((v) => formatDisplayValue(v)).join(', ')
                : formatDisplayValue(propValue) || label}
            </span>
            <div className="flex items-center gap-1">
              {(propValue || (mode === 'multiple' && isArray(propValue) && propValue.length > 0)) && !disabled && (
                <X
                  className="h-4 w-4 text-muted-foreground hover:text-foreground"
                  onClick={handleClear}
                />
              )}
              <ChevronDown className="h-4 w-4 text-muted-foreground" />
            </div>
          </div>
        </PopoverTrigger>
        <PopoverContent
          className="p-0 w-full min-w-[200px]"
          align="start"
          onOpenAutoFocus={(e) => e.preventDefault()}
        >
          <div className="p-2">
            {/* 搜索输入框 */}
            <input
              ref={searchInputRef}
              type="text"
              value={inputSearchValue}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => setInputSearchValue(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="搜索..."
              className={cn(
                'w-full h-9 px-3 py-1 text-sm bg-background border border-input rounded-md',
                'focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2',
                'placeholder:text-muted-foreground'
              )}
            />

            {/* 选项列表 */}
            <div
              ref={dropdownRef}
              className="mt-1 max-h-60 overflow-y-scroll"
              onWheel={(e) => e.stopPropagation()}
            >
              {loading && filteredOptions.length === 0 ? (
                <div className="flex items-center justify-center p-4">
                  <Loader2 className="h-4 w-4 animate-spin" />
                  <span className="ml-2 text-sm">加载中...</span>
                </div>
              ) : filteredOptions.length === 0 ? (
                <div className="p-4 text-center text-sm text-muted-foreground">
                  {inputSearchValue ? '未找到匹配项' : '暂无数据'}
                </div>
              ) : (
                <>
                  {filteredOptions.map((option: RelateFieldOption, index: number) => {
                    const isSelected = mode === 'multiple'
                      ? isArray(propValue) && propValue.some((v: any) => v?.key === option.value)
                      : (propValue as any)?.key === option.value
                    return (
                      <div
                        key={option.value}
                        className={cn(
                          'flex items-center px-3 py-2 text-sm cursor-pointer rounded-md',
                          'hover:bg-accent hover:text-accent-foreground',
                          highlightedIndex === index && 'bg-accent',
                          isSelected && 'bg-accent text-accent-foreground'
                        )}
                        onClick={() => handleSelectOption(option)}
                        onMouseEnter={() => setHighlightedIndex(index)}
                      >
                        {mode === 'multiple' && (
                          <input
                            type="checkbox"
                            checked={isSelected}
                            readOnly
                            className="mr-2"
                          />
                        )}
                        <span className="truncate">{option.label}</span>
                      </div>
                    )
                  })}
                  {loading && page > 0 && (
                    <div className="flex items-center justify-center p-2 text-sm text-muted-foreground">
                      <Loader2 className="h-3 w-3 animate-spin mr-1" />
                      加载中...
                    </div>
                  )}
                  {!loading && !hasMore && page > 0 && (
                    <div className="text-center p-2 text-sm text-muted-foreground">
                      已加载全部
                    </div>
                  )}
                  {hasMore && !loading && (
                    <div className="text-center p-2">
                      <Button variant="ghost" size="sm" onClick={loadMore} disabled={pageLoading} className="w-full">
                        {pageLoading ? (
                          <>
                            <Loader2 className="h-3 w-3 animate-spin mr-1" />
                            加载中...
                          </>
                        ) : (
                          '加载更多'
                        )}
                      </Button>
                    </div>
                  )}
                </>
              )}
            </div>
          </div>
        </PopoverContent>
      </Popover>
    </div>
  )
}

export default AsyncSelect

import isEmpty from 'lodash/isEmpty'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'
import { getQueryFilter } from './filter-utils'

/**
 * 在 tableSchema 中查找 value?.relate?.id 等于 tableID 的对应 key
 */
export const findRelateKeyInTableSchema = (tableSchema: any, tableID: string): string | null => {
  if (!tableSchema || !tableSchema.properties) {
    return null
  }

  for (const [key, property] of Object.entries(tableSchema.properties)) {
    if ((property as any)?.relate?.id === tableID) {
      return key
    }
  }

  return null
}

/**
 * 在树形数据中查找节点
 */
export const findTreeNode = (treeData: any[], value: any): any => {
  for (const node of treeData) {
    if (node.value === value) {
      return node
    }
    if (node.children && node.children.length > 0) {
      const found = findTreeNode(node.children, value)
      if (found) return found
    }
  }
  return null
}

/**
 * 替换字段占位符
 * 将 [field]:fieldName 或 [field][table]:fieldName 替换为实际值
 */
export const replaceFieldPlaceholders = (value: any, allValues: Record<string, any>): any => {
  if (typeof value === 'string') {
    // 处理 [field]:fieldName 占位符
    if (value.startsWith('[field]:')) {
      const key = value.substring(8)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    // 处理 [field][table]:fieldName 占位符
    if (value.startsWith('[field][table]:')) {
      const key = value.substring(15)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    return value
  }

  if (isArray(value)) {
    return value.map(item => replaceFieldPlaceholders(item, allValues))
  }

  if (isObject(value) && value !== null) {
    const result: Record<string, any> = {}
    for (const [key, val] of Object.entries(value)) {
      result[key] = replaceFieldPlaceholders(val, allValues)
    }
    return result
  }

  return value
}

/**
 * 处理过滤器
 * 将内置查询过滤器应用到 filterObj 中
 *
 * @param filterObj - 过滤器对象，会被修改
 * @param field - 字段配置
 * @param getFormState - 获取表单状态的函数
 * @param outTable - 外部表的 editingSchema（可选）
 */
export const dealFilter = (
  filterObj: Record<string, any>,
  field: any,
  getFormState?: () => any,
  outTable?: { editingSchema?: Record<string, any> }
) => {
  // 在过滤器中，如果没有设置 field.filter，则使用内置查询
  const ifFilter = field.filter

  // 设置了内置查询
  if (field.insideFilter && !ifFilter) {
    const inFilter = getQueryFilter(field.insideFilter, field.schema)
    const allValues = {
      ...(outTable?.editingSchema || {}),
      ...(getFormState?.()?.values || {})
    }

    // 确保 filterObj 有 search 属性
    if (!filterObj.search) {
      filterObj.search = {}
    }

    // 替换占位符并添加到搜索条件中
    for (const key in inFilter) {
      let insideVal = inFilter[key]
      const replacedVal = replaceFieldPlaceholders(insideVal, allValues)
      filterObj.search[key] = replacedVal
    }
  }
}

/**
 * 简单的 fieldRender 函数
 * 用于在列表中显示字段值
 */
export const fieldRender = (value: any, _schema?: any): React.ReactNode => {
  // 字符串、数字、布尔值直接显示
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return value
  }

  // 对象显示 .name
  if (isObject(value) && !isArray(value)) {
    return (value as any).name ?? (value as any).id ?? JSON.stringify(value)
  }

  // 数组显示 .name join(',')
  if (isArray(value)) {
    return value
      .map(item => {
        if (typeof item === 'string' || typeof item === 'number') {
          return item
        }
        if (isObject(item)) {
          return (item as any).name ?? (item as any).id
        }
        return JSON.stringify(item)
      })
      .filter(Boolean)
      .join(',')
  }

  // 空值处理
  if (isEmpty(value)) {
    return null
  }

  return JSON.stringify(value)
}

/**
 * 获取表单状态 - 用于获取其他字段的值
 * 类似于 use('form') 的功能
 */
export const getFormState = (formState: any, currentFieldKey?: string) => {
  // TODO: 实现表单状态获取逻辑
  // 这个函数应该从 form state 中获取其他字段的值
  // 用于字段联动和脚本计算
  if (!formState) {
    return {}
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    // 跳过当前字段，避免循环依赖
    if (key !== currentFieldKey) {
      values[key] = formState.values[key]
    }
  }

  return { values }
}

/**
 * 获取表单所有值 - 用于字段脚本
 */
export const getFormValues = (schema: any, formState?: any) => {
  if (!formState) {
    return null
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    if (key !== schema.key) {
      values[key] = formState.values[key]
    }
  }

  return values
}

/**
 * Schema 转换器
 * 将关联字段的 schema 转换为组件可用的格式
 */
export const schemaConverter = (
  schema: any,
  options?: { tableSchema?: any }
): {
  type: string
  schema: { name: string }
  fieldSchema?: any
  relateSchema: any
  tableID: string
  displayField: string
  relateTableName: string
  insideFilter?: any
  relateShowFields?: any[]
  selectType?: 'single' | 'multiple'
  key?: string
} | null => {
  if (
    !['object', 'array'].includes(schema.type) ||
    !schema.relate?.id ||
    schema.recordSelectType
  ) {
    return null
  }

  const relate = schema.relate
  const relateShowFields = schema.relateShowFields
  const id = relate.id
  const fieldSchema = relate.fields?.[0]?.fieldSchema

  const result: any = {
    type: schema.selectType === 'multiple' ? 'relate_multi_select' : 'relate_fkselect',
    schema: { name: `core/t/${id}/d` },
    fieldSchema,
    relateSchema: schema,
    tableID: id,
    displayField: relate.fields?.[0]?.key || 'name',
    relateTableName: id,
    insideFilter: schema.insideFilter,
  }

  // 使用 findRelateKeyInTableSchema 查找关联键
  if (options?.tableSchema) {
    const relateKey = findRelateKeyInTableSchema(options.tableSchema, relate.id)
    if (relateKey) {
      result.key = relateKey
    }
  }

  // 多字段
  if (relateShowFields && relateShowFields.length > 0) {
    result.type = 'relate_list_fkselect'
    result.relateShowFields = relateShowFields
    result.selectType = schema.selectType
  }

  return result
}

