import isEmpty from 'lodash/isEmpty'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'
import { getQueryFilter } from './filter-utils'

/**
 * 在 tableSchema 中查找 value?.relate?.id 等于 tableID 的对应 key
 */
export const findRelateKeyInTableSchema = (tableSchema: any, tableID: string): string | null => {
  if (!tableSchema || !tableSchema.properties) {
    return null
  }

  for (const [key, property] of Object.entries(tableSchema.properties)) {
    if ((property as any)?.relate?.id === tableID) {
      return key
    }
  }

  return null
}

/**
 * 在树形数据中查找节点
 */
export const findTreeNode = (treeData: any[], value: any): any => {
  for (const node of treeData) {
    if (node.value === value) {
      return node
    }
    if (node.children && node.children.length > 0) {
      const found = findTreeNode(node.children, value)
      if (found) return found
    }
  }
  return null
}

/**
 * 替换字段占位符
 * 将 [field]:fieldName 或 [field][table]:fieldName 替换为实际值
 */
export const replaceFieldPlaceholders = (value: any, allValues: Record<string, any>): any => {
  if (typeof value === 'string') {
    // 处理 [field]:fieldName 占位符
    if (value.startsWith('[field]:')) {
      const key = value.substring(8)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    // 处理 [field][table]:fieldName 占位符
    if (value.startsWith('[field][table]:')) {
      const key = value.substring(15)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    return value
  }

  if (isArray(value)) {
    return value.map(item => replaceFieldPlaceholders(item, allValues))
  }

  if (isObject(value) && value !== null) {
    const result: Record<string, any> = {}
    for (const [key, val] of Object.entries(value)) {
      result[key] = replaceFieldPlaceholders(val, allValues)
    }
    return result
  }

  return value
}

/**
 * 处理过滤器
 * 将内置查询过滤器应用到 filterObj 中
 *
 * @param filterObj - 过滤器对象，会被修改
 * @param field - 字段配置
 * @param getFormState - 获取表单状态的函数
 * @param outTable - 外部表的 editingSchema（可选）
 */
export const dealFilter = (
  filterObj: Record<string, any>,
  field: any,
  getFormState?: () => any,
  outTable?: { editingSchema?: Record<string, any> }
) => {
  // 在过滤器中，如果没有设置 field.filter，则使用内置查询
  const ifFilter = field.filter

  // 设置了内置查询
  if (field.insideFilter && !ifFilter) {
    const inFilter = getQueryFilter(field.insideFilter, field.schema)
    const allValues = {
      ...(outTable?.editingSchema || {}),
      ...(getFormState?.()?.values || {})
    }

    // 确保 filterObj 有 search 属性
    if (!filterObj.search) {
      filterObj.search = {}
    }

    // 替换占位符并添加到搜索条件中
    for (const key in inFilter) {
      let insideVal = inFilter[key]
      const replacedVal = replaceFieldPlaceholders(insideVal, allValues)
      filterObj.search[key] = replacedVal
    }
  }
}

/**
 * 简单的 fieldRender 函数
 * 用于在列表中显示字段值
 */
export const fieldRender = (value: any, _schema?: any): React.ReactNode => {
  // 字符串、数字、布尔值直接显示
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return value
  }

  // 对象显示 .name
  if (isObject(value) && !isArray(value)) {
    return (value as any).name ?? (value as any).id ?? JSON.stringify(value)
  }

  // 数组显示 .name join(',')
  if (isArray(value)) {
    return value
      .map(item => {
        if (typeof item === 'string' || typeof item === 'number') {
          return item
        }
        if (isObject(item)) {
          return (item as any).name ?? (item as any).id
        }
        return JSON.stringify(item)
      })
      .filter(Boolean)
      .join(',')
  }

  // 空值处理
  if (isEmpty(value)) {
    return null
  }

  return JSON.stringify(value)
}

/**
 * 获取表单状态 - 用于获取其他字段的值
 * 类似于 use('form') 的功能
 */
export const getFormState = (formState: any, currentFieldKey?: string) => {
  // TODO: 实现表单状态获取逻辑
  // 这个函数应该从 form state 中获取其他字段的值
  // 用于字段联动和脚本计算
  if (!formState) {
    return {}
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    // 跳过当前字段，避免循环依赖
    if (key !== currentFieldKey) {
      values[key] = formState.values[key]
    }
  }

  return { values }
}

/**
 * 获取表单所有值 - 用于字段脚本
 */
export const getFormValues = (schema: any, formState?: any) => {
  if (!formState) {
    return null
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    if (key !== schema.key) {
      values[key] = formState.values[key]
    }
  }

  return values
}

/**
 * Schema 转换器
 * 将关联字段的 schema 转换为组件可用的格式
 */
export const schemaConverter = (
  schema: any,
  options?: { tableSchema?: any }
): {
  type: string
  schema: { name: string }
  fieldSchema?: any
  relateSchema: any
  tableID: string
  displayField: string
  relateTableName: string
  insideFilter?: any
  relateShowFields?: any[]
  selectType?: 'single' | 'multiple'
  key?: string
} | null => {
  if (
    !['object', 'array'].includes(schema.type) ||
    !schema.relate?.id ||
    schema.recordSelectType
  ) {
    return null
  }

  const relate = schema.relate
  const relateShowFields = schema.relateShowFields
  const id = relate.id
  const fieldSchema = relate.fields?.[0]?.fieldSchema

  const result: any = {
    type: schema.selectType === 'multiple' ? 'relate_multi_select' : 'relate_fkselect',
    schema: { name: `core/t/${id}/d` },
    fieldSchema,
    relateSchema: schema,
    tableID: id,
    displayField: relate.fields?.[0]?.key || 'name',
    relateTableName: id,
    insideFilter: schema.insideFilter,
  }

  // 使用 findRelateKeyInTableSchema 查找关联键
  if (options?.tableSchema) {
    const relateKey = findRelateKeyInTableSchema(options.tableSchema, relate.id)
    if (relateKey) {
      result.key = relateKey
    }
  }

  // 多字段
  if (relateShowFields && relateShowFields.length > 0) {
    result.type = 'relate_list_fkselect'
    result.relateShowFields = relateShowFields
    result.selectType = schema.selectType
  }

  return result
}

import * as React from 'react'
import isEmpty from 'lodash/isEmpty'
import isPlainObject from 'lodash/isPlainObject'
import isArray from 'lodash/isArray'
import pick from 'lodash/pick'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog'
import { Plus, Repeat2 } from 'lucide-react'
import { useUser } from '@airiot/client'
import { createAPI } from '@airiot/client'
import { getFormValues, dealFilter } from '@/registry/lib/form-relate-utils'
import type { RelateFieldProps } from '@/registry/lib/form-relate-types'

interface RelateModelSelectProps extends RelateFieldProps {
  label?: string
  schema?: any
  inputType?: 'select' | 'button'
  selectType?: 'single' | 'multiple'
  allFieldReturn?: boolean
  insideFilter?: any
}

/**
 * RelateModelSelect - 弹窗表格选择器
 * 外部工作表关联，多字段展示，弹窗选择
 */
const RelateModelSelect: React.FC<RelateModelSelectProps> = (props) => {
  const {
    input,
    field = {},
    label,
    disabled: propsDisabled,
    inputType = 'select',
    selectType = 'single',
    allFieldReturn = false,
  } = props

  const { onChange, value } = input || {}
  const { displayField = 'name', relateShowFields, fieldSchema, schema } = field

  const { user } = useUser()

  // 获取表单状态
  const [formState] = React.useState<Record<string, any>>({})

  const disabled = propsDisabled || (field.schema as any)?.disabled || false

  // 弹窗状态
  const [visible, setVisible] = React.useState(false)
  const [loading, setLoading] = React.useState(false)
  const [data, setData] = React.useState<any[]>([])
  const [selectedIds, setSelectedIds] = React.useState<string[]>([])

  // 默认值生效
  React.useEffect(() => {
    const defaultVal = (field.schema as any)?.defaultVal
    setTimeout(() => {
      if (!value && defaultVal && onChange) {
        onChange(defaultVal)
      }
    })
  }, [])

  // 字段脚本部分
  React.useEffect(() => {
    const values = getFormValues(field.schema, { values: formState })
    if (values && !isEmpty(values)) {
      // TODO: 实现字段脚本逻辑
      // useScriptVal({ schema: field.schema, value, values, record, onChange })
    }
  }, [JSON.stringify(formState)])

  // 多字段联动表单其他字段
  React.useEffect(() => {
    relateShowFields?.forEach((rsf: any) => {
      if (rsf.mapToCurrent && rsf.mapField && value?.[rsf.key]) {
        // TODO: 触发表单字段变化
        // form?.change(rsf.mapField, value[rsf.key])
      }
    })
  }, [JSON.stringify(value || {}), relateShowFields])

  // 加载数据
  const loadData = React.useCallback(async () => {
    if (!schema) return

    setLoading(true)
    let filterObj: any = {}

    dealFilter(filterObj, field, () => ({ values: formState }))

    try {
      const tableName = schema.name
      if (!tableName) {
        console.warn('缺少 schema.name')
        return
      }

      const extraFields = relateShowFields?.map((f: any) => f.key) || []

      // 创建 API 实例
      const api = createAPI({
        resource: tableName,
        name: 'relate'
      })

      // 使用 api.query 查询数据
      const { items } = await api.query(
        {
          limit: 100,
          fields: ['id', displayField, ...extraFields].filter(Boolean),
          ...Object.keys(filterObj).length > 0 && { search: filterObj }
        }
      )

      setData(items || [])
    } catch (error) {
      console.error('加载数据失败:', error)
      setData([])
    } finally {
      setLoading(false)
    }
  }, [schema, JSON.stringify(field), JSON.stringify(formState), displayField, relateShowFields])

  // 打开弹窗时加载数据
  React.useEffect(() => {
    if (visible) {
      loadData()
    }
  }, [visible, loadData])

  // 格式化显示值
  const formatDisplayValue = (val: any): string => {
    if (!val) return ''
    if (isPlainObject(val)) {
      return val[displayField] || val.id || ''
    }
    return String(val)
  }

  // 单选确认
  const selectOne = (item: any) => {
    setVisible(false)

    if (allFieldReturn) {
      const val = { ...item }
      delete val.deletePermission
      delete val.editPermission
      onChange?.(val)
      return
    }

    const v = item[displayField]
    let r = v
      ? {
          id: item.id,
          [displayField]: v,
          ...pick(item, relateShowFields?.map((s: any) => s.key) || []),
        }
      : null

    if (v && fieldSchema && (fieldSchema as any).enum) {
      const enumList = (fieldSchema as any).enum
      const enumTitle = (fieldSchema as any).enum_title || []
      const i = enumList.indexOf(v)
      const title = enumTitle[i]
      if (title) (r as any).name = title
    }

    if (field.displayField && item[field.displayField]) {
      (r as any)[field.displayField] = item[field.displayField]
    }

    v && onChange?.(r)
  }

  // 多选确认
  const selectMany = (selectedItems: any[]) => {
    setVisible(false)

    if (!selectedItems || selectedItems.length === 0) {
      onChange?.(null)
      return
    }

    let resultList: any[] = []

    selectedItems.forEach((item) => {
      if (allFieldReturn) {
        const val = { ...item }
        delete val.deletePermission
        delete val.editPermission
        resultList.push(val)
        return
      }

      const v = item[displayField]
      let r = v
        ? {
            id: item.id,
            [displayField]: v,
            ...pick(item, relateShowFields?.map((s: any) => s.key) || []),
          }
        : null

      if (v && fieldSchema && (fieldSchema as any).enum) {
        const enumList = (fieldSchema as any).enum
        const enumTitle = (fieldSchema as any).enum_title || []
        const i = enumList.indexOf(v)
        const title = enumTitle[i]
        if (title) (r as any).name = title
      }

      if (field.displayField && item[field.displayField]) {
        (r as any)[field.displayField] = item[field.displayField]
      }

      v && resultList.push(r)
    })

    onChange?.(resultList)
  }

  // 获取当前选中的值（用于显示）
  const getSelectedDisplay = () => {
    if (selectType === 'multiple') {
      if (isArray(value) && value.length > 0) {
        return value.map((v: any) => formatDisplayValue(v)).join(', ')
      }
      return ''
    } else {
      return formatDisplayValue(value)
    }
  }

  const BtnIcon = value ? <Repeat2 className="h-4 w-4" /> : <Plus className="h-4 w-4" />

  return (
    <>
      {inputType === 'button' ? (
        <Button disabled={disabled} onClick={() => !disabled && setVisible(true)} type="button">
          <span className="mr-2">{BtnIcon}</span>
          记录
        </Button>
      ) : (
        <div className="relative">
          <Input
            value={getSelectedDisplay()}
            placeholder={label}
            readOnly
            disabled={disabled}
            onClick={() => !disabled && setVisible(true)}
            className="cursor-pointer"
          />
          {value && (
            <Button
              variant="ghost"
              size="icon"
              className="absolute right-0 top-1/2 -translate-y-1/2 h-full px-3"
              onClick={() => onChange?.(null)}
              disabled={disabled}
            >
              ✕
            </Button>
          )}
        </div>
      )}

      <Dialog open={visible} onOpenChange={setVisible}>
        <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{label || '选择记录'}</DialogTitle>
          </DialogHeader>

          {loading ? (
            <div className="flex items-center justify-center py-8">
              <div className="text-center">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-2"></div>
                <p className="text-sm text-muted-foreground">加载中...</p>
              </div>
            </div>
          ) : data.length === 0 ? (
            <div className="flex items-center justify-center py-8">
              <p className="text-sm text-muted-foreground">暂无数据</p>
            </div>
          ) : (
            <div className="space-y-4">
              {/* 数据列表 */}
              <div className="border rounded-md">
                <table className="w-full">
                  <thead className="bg-muted">
                    <tr>
                      {selectType === 'multiple' && (
                        <th className="p-2 text-left w-12">
                          <input
                            type="checkbox"
                            checked={selectedIds.length === data.length && data.length > 0}
                            onChange={(e) => {
                              if (e.target.checked) {
                                setSelectedIds(data.map((item) => item.id))
                              } else {
                                setSelectedIds([])
                              }
                            }}
                          />
                        </th>
                      )}
                      <th className="p-2 text-left">{displayField}</th>
                      {relateShowFields?.map((f: any) => (
                        <th key={f.key} className="p-2 text-left">
                          {f.title}
                        </th>
                      ))}
                      {selectType === 'single' && <th className="p-2 text-left w-20">操作</th>}
                    </tr>
                  </thead>
                  <tbody>
                    {data.map((item) => (
                      <tr key={item.id} className="border-t hover:bg-muted/50">
                        {selectType === 'multiple' && (
                          <td className="p-2">
                            <input
                              type="checkbox"
                              checked={selectedIds.includes(item.id)}
                              onChange={(e) => {
                                if (e.target.checked) {
                                  setSelectedIds([...selectedIds, item.id])
                                } else {
                                  setSelectedIds(selectedIds.filter((id) => id !== item.id))
                                }
                              }}
                            />
                          </td>
                        )}
                        <td className="p-2">{item[displayField]}</td>
                        {relateShowFields?.map((f: any) => (
                          <td key={f.key} className="p-2">
                            {item[f.key]}
                          </td>
                        ))}
                        {selectType === 'single' && (
                          <td className="p-2">
                            <Button size="sm" variant="outline" onClick={() => selectOne(item)}>
                              选择
                            </Button>
                          </td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          <DialogFooter>
            <Button variant="outline" onClick={() => setVisible(false)} type="button">
              取消
            </Button>
            {selectType === 'multiple' && (
              <Button
                onClick={() => {
                  const selectedItems = data.filter((item) => selectedIds.includes(item.id))
                  selectMany(selectedItems)
                }}
                type="button"
              >
                确定
              </Button>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  )
}

