import { cn } from "@/lib/utils"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { X } from "lucide-react"

interface Schema {
  enum?: string[]
  enumNames?: Record<string, string>
}

export interface FormSelectProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange" | "onBlur" | "onFocus"> {
  /**
   * 当前值
   */
  value?: string
  /**
   * 默认值
   */
  defaultValue?: string
  /**
   * 占位符
   */
  placeholder?: string
  /**
   * 选项列表
   */
  options?: Array<{ value: string; label?: string; name?: string; disabled?: boolean }>
  /**
   * 尺寸
   */
  size?: "sm" | "default" | undefined
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 是否只读
   */
  readOnly?: boolean
  /**
   * 是否显示边框
   */
  bordered?: boolean
  /**
   * 是否显示清除按钮
   */
  allowClear?: boolean
  /**
   * 是否支持搜索
   */
  showSearch?: boolean
  /**
   * 是否显示下拉箭头
   */
  showArrow?: boolean
  /**
   * 是否自动获取焦点
   */
  autoFocus?: boolean
  /**
   * 默认是否展开
   */
  defaultOpen?: boolean
  /**
   * 下拉菜单和选择器同宽
   */
  dropdownMatchSelectWidth?: boolean
  /**
   * 值改变时的回调
   */
  onChange?: (value: string) => void
  /**
   * 失去焦点时的回调
   */
  onBlur?: () => void
  /**
   * 获得焦点时的回调
   */
  onFocus?: () => void
  schema?: Schema
}

const FormSelect = React.forwardRef<HTMLDivElement, FormSelectProps>(
  ({
    className,
    size,
    value,
    defaultValue,
    placeholder = "请选择",
    disabled = false,
    readOnly = false,
    bordered = true,
    allowClear = false,
    showSearch = false,
    showArrow = true,
    autoFocus = false,
    defaultOpen = false,
    dropdownMatchSelectWidth = true,
    onChange,
    onBlur,
    onFocus,
    schema,
    ...props
  }, ref) => {
    const [internalValue, setInternalValue] = React.useState(defaultValue || "")
    const [isOpen, setIsOpen] = React.useState(defaultOpen)
    const [searchValue, setSearchValue] = React.useState("")
    const selectRef = React.useRef<HTMLButtonElement>(null)

    let options: Array<{ value: string; label?: string; name?: string; disabled?: boolean }> = []
    if (props?.options) {
      options = props.options
    } else if (schema?.enum) {
      options = schema.enum.map((k: string) => {
        const names = schema.enumNames
        return { label: names?.[k] || k, value: k }
      })
    }

    const handleValueChange = (newValue: string) => {
      if (readOnly) return
      setInternalValue(newValue)
      setSearchValue("") // 选择后清空搜索
      onChange?.(newValue)
    }

    const handleClear = (e: React.MouseEvent) => {
      e.stopPropagation()
      e.preventDefault()
      if (readOnly) return
      setInternalValue("")
      setSearchValue("")
      setIsOpen(false) // 确保清除后Select关闭
      onChange?.("")
    }

    const handleSearchChange = (value: string) => {
      setSearchValue(value)
    }

    const currentValue = value !== undefined ? value : internalValue
    const showClear = allowClear && currentValue && !disabled && !readOnly

    // 过滤选项
    const filteredOptions = React.useMemo(() => {
      if (!showSearch || !searchValue.trim()) {
        return options
      }
      return options.filter(option => {
        const label = option.label || option.name || ''
        return label.toLowerCase().includes(searchValue.toLowerCase()) ||
          option.value.toLowerCase().includes(searchValue.toLowerCase())
      })
    }, [options, searchValue, showSearch])

    return (
      <Select
        value={currentValue}
        onValueChange={handleValueChange}
        disabled={disabled || readOnly}
        open={isOpen}
        onOpenChange={(open) => {
          setIsOpen(open)
          if (open) {
            onFocus?.()
          } else {
            onBlur?.()
          }
        }}
      >
        <div className="relative">
          <SelectTrigger
            ref={selectRef}
            className={cn(
              "w-full",
              !bordered && "border-transparent",
              className
            )}
            size={size}
            aria-invalid={props['aria-invalid']}
          >
