const MapContainer = React.forwardRef<HTMLDivElement, MapContainerProps>(
  (
    {
      className,
      viewOptions = {
        position: {
          center: DEFAULT_CENTER,
          pick: false
        },
        zoom: 10,
        maxZoom: 18,
        minZoom: 3,
        rotation: 0,
        recordRotationActive: false,
        animation: true,
        duration: 1000
      },
      zoomOption = {
        show: true,
        zoomInTipLabel: '放大',
        zoomOutTipLabel: '缩小',
