                        }

                        const createElementCode = `React.createElement("${tagName}", ${propsObj}${childrenArgs})`;
                        const placeholder = generatePlaceholder(createElementCode);

                        // 替换当前匹配项
                        processed = processed.replace(fullMatch, placeholder);

