import * as React from "react"
import { cn } from "@/lib/utils"
import { useUser } from "@airiot/client"

export interface IframeProps extends React.IframeHTMLAttributes<HTMLIFrameElement> {
  /**
   * iframe 地址
   */
  iframeSrc?: string
  /**
   * 携带 token
   */
  hasToken?: boolean
}

const Iframe = React.forwardRef<HTMLIFrameElement, IframeProps>(
  (
    {
      className,
      iframeSrc = '',
      hasToken = false,
      ...props
    },
    ref
  ) => {
    // 获取 token
    const token = useUser().user?.token || ''

    // 构建 URL
    const buildSrc = React.useMemo(() => {
      let src = iframeSrc

      // 添加 token
      if (hasToken && token && src) {
        const separator = src.indexOf('?') > 0 ? '&' : '?'
        src = `${src}${separator}token=${token}`
      }

      return src
    }, [iframeSrc, hasToken, token])

    // 如果没有 URL，显示占位提示
    if (!buildSrc) {
      return (
        <div
          className={cn(
            "flex items-center justify-center bg-slate-50 border-2 border-dashed border-slate-300 rounded-lg",
            className
          )}
          style={{ width: '100%', height: '100%', minHeight: '200px' }}
        >
          <p className="text-sm text-slate-500 text-center px-4">
            用于嵌入网页内容，嵌入的网址的页面展示内容会在 iframe 窗口内显示
          </p>
        </div>
      )
    }

    return (
      <iframe
        ref={ref}
        src={buildSrc}
        className={cn("w-full h-full border-0", className)}
        frameBorder="0"
        allowFullScreen
        allowTransparency
        {...props}
      />
    )
  }
)

Iframe.displayName = "Iframe"

export { Iframe }

import * as React from "react"
import { cn } from "@/lib/utils"

export interface ImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  /**
   * 图片地址
   */
  src?: string
  /**
   * 增加浏览器参数（避免缓存）
   */
  addParameters?: boolean
  /**
   * SVG 内容（用于内联 SVG）
   */
  svgContent?: string
  /**
   * 等比缩放（仅 SVG）
   */
  preserveAspectRatio?: boolean
  /**
   * 背景颜色
   */
  backgroundColor?: string
  /**
   * 占位提示
   */
  alt?: string
}

const Image = React.forwardRef<HTMLImageElement, ImageProps>(
  (
    {
      className,
      src = '',
      addParameters = false,
      svgContent,
      preserveAspectRatio = true,
      backgroundColor = '',
      alt = '图片',
      ...props
    },
    ref
  ) => {
    // 处理图片 URL（添加时间戳避免缓存）
    const imageSrc = React.useMemo(() => {
      if (!src) return ''

      if (addParameters) {
        const separator = src.indexOf('?') > 0 ? '&' : '?'
        return `${src}${separator}t=${new Date().getTime()}`
      }

      return src
    }, [src, addParameters])

    // 判断是否为 SVG
    const isSvg = React.useMemo(() => {
      return typeof src === 'string' && src.includes('.svg')
    }, [src])

    // 渲染 SVG
    if (isSvg && svgContent) {
      return (
        <div
          className={cn("image-container", className)}
          style={{
            background: backgroundColor || undefined,
            width: '100%',
            height: '100%'
          }}
          {...props}
          dangerouslySetInnerHTML={{ __html: svgContent }}
        />
      )
    }

    // 渲染普通图片
    return (
      <div
        className={cn("image-wrapper", className)}
        style={{ width: '100%', height: '100%' }}
        {...props}
      >
        {src ? (
          <img
            ref={ref}
            src={imageSrc}
            alt={alt}
            className={cn("image-component", className)}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'contain',
              backgroundColor: backgroundColor || undefined,
              userSelect: 'none',
              draggable: false
            }}
            {...props}
          />
        ) : (
          <div
            className={cn(
              "image-placeholder flex items-center justify-center border-2 border-dashed border-slate-300 rounded-lg",
              className
            )}
            style={{
              width: '100%',
              height: '100%',
              backgroundColor: backgroundColor || undefined
            }}
          >
            <p className="text-sm text-slate-500">请上传图片</p>
          </div>
        )}
      </div>
    )
  }
)

