          })
          columns.push({
            items: dayItems,
            value: currentDay,
            onChange: (v) => updatePendingDate('day', v)
          })
          break
        case 'hour':
          columns.push({
            items: yearItems,
            value: currentYear,
            onChange: (v) => updatePendingDate('year', v)
          })
          columns.push({
            items: monthItems,
            value: currentMonth,
            onChange: (v) => updatePendingDate('month', v)
          })
          columns.push({
            items: dayItems,
            value: currentDay,
            onChange: (v) => updatePendingDate('day', v)
          })
          columns.push({
            items: hourItems,
            value: currentHour,
            onChange: (v) => updatePendingDate('hour', v)
          })
          break
        case 'minute':
          columns.push({
            items: yearItems,
            value: currentYear,
            onChange: (v) => updatePendingDate('year', v)
          })
          columns.push({
            items: monthItems,
            value: currentMonth,
            onChange: (v) => updatePendingDate('month', v)
          })
          columns.push({
            items: dayItems,
            value: currentDay,
            onChange: (v) => updatePendingDate('day', v)
          })
          columns.push({
            items: hourItems,
            value: currentHour,
            onChange: (v) => updatePendingDate('hour', v)
          })
          columns.push({
            items: minuteItems,
            value: currentMinute,
            onChange: (v) => updatePendingDate('minute', v)
          })
          break
        case 'second':
          columns.push({
            items: yearItems,
            value: currentYear,
            onChange: (v) => updatePendingDate('year', v)
          })
          columns.push({
            items: monthItems,
            value: currentMonth,
            onChange: (v) => updatePendingDate('month', v)
          })
          columns.push({
            items: dayItems,
            value: currentDay,
            onChange: (v) => updatePendingDate('day', v)
          })
          columns.push({
            items: hourItems,
            value: currentHour,
            onChange: (v) => updatePendingDate('hour', v)
          })
          columns.push({
            items: minuteItems,
            value: currentMinute,
            onChange: (v) => updatePendingDate('minute', v)
          })
          columns.push({
            items: secondItems,
            value: currentSecond,
            onChange: (v) => updatePendingDate('second', v)
          })
          break
      }
      return (
        <div
          onPointerDownCapture={(e) => e.stopPropagation()}
          onPointerMoveCapture={(e) => e.stopPropagation()}
          onPointerUpCapture={(e) => e.stopPropagation()}
        >
          <div className="flex justify-between items-center px-4 py-2 border-b">
            <button
              type="button"
              className="text-primary px-3 py-1"
              onClick={() => setVisible(false)}
            >
              取消
            </button>
            <button
              type="button"
              className="text-primary px-3 py-1"
              onClick={handleConfirm}
            >
              确定
            </button>
          </div>
          <div className="flex py-2" style={{ touchAction: 'none' }}>
            {columns.map((column, index) => (
              <WheelColumn
                key={index}
                visible={visible}
                items={column.items}
                value={column.value}
                onChange={column.onChange}
              />
            ))}
          </div>
        </div>
      )
    }

    const displayValue = dateStr || '请选择'

    return (
      <div ref={ref} className={cn("w-full", className)} {...props}>
        <div
          className={cn(
            "flex items-center justify-between px-4 py-3 bg-background border rounded-md cursor-pointer",
