const Status = React.forwardRef<HTMLDivElement, StatusProps>(
  (
    {
      className,
      value,
      statuses = [],
      blinkOnStateChange = false,
      width,
      height,
      ...props
    },
    ref
  ) => {
    const prevStatusRef = React.useRef<StatusConfig | null>(null)
    const [isBlinking, setIsBlinking] = React.useState(false)
    const audioRef = React.useRef<HTMLAudioElement | null>(null)

    // 查找匹配的状态
    const currentStatus = React.useMemo(() => {
      if (!statuses || statuses.length === 0) {
        return null
      }

      // 如果 value 未定义，返回默认状态（activeValue 为 'false' 或 '0' 的状态）
      if (value === undefined || value === null) {
        return statuses.find(
          (s) => s.activeValue === 'false' || s.activeValue === '0' || s.activeValue === false
        ) || null
      }

      // 遍历状态数组，找到第一个匹配的状态
      for (const status of statuses) {
        if (!status.activeType) {
          // 如果没有指定类型，默认使用固定值匹配
          if (status.activeValue === value) {
            return status
          }
        } else if (status.activeType === 'value') {
          // 固定值匹配
          if (status.activeValue === value) {
            return status
          }
        } else if (status.activeType === 'range') {
          // 范围匹配（左闭右开区间）
          if (
            typeof value === 'number' &&
            status.minValue !== undefined &&
            status.maxValue !== undefined
          ) {
            if (value >= status.minValue && value < status.maxValue) {
              return status
            }
          }
        }
      }

      return null
    }, [value, statuses])

    // 状态切换时触发闪烁动画和播放音频
    React.useEffect(() => {
      if (currentStatus && currentStatus !== prevStatusRef.current) {
        // 触发闪烁动画
        if (blinkOnStateChange) {
          setIsBlinking(true)
          setTimeout(() => {
            setIsBlinking(false)
          }, 2000)
        }

        // 播放音频
        if (currentStatus.audioSrc) {
          // 停止之前的音频
          if (audioRef.current) {
            audioRef.current.pause()
            audioRef.current.currentTime = 0
          }

          // 创建并播放新音频
          const audio = new Audio(currentStatus.audioSrc)
          audioRef.current = audio
          audio.play().catch((error) => {
            console.warn('音频播放失败:', error)
          })
        }
      }
      prevStatusRef.current = currentStatus
    }, [currentStatus, blinkOnStateChange])

    // 计算样式
    const containerStyle = React.useMemo(() => {
      const style: React.CSSProperties = {
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundRepeat: 'no-repeat',
        backgroundSize: '100% 100%',
      }

      if (width !== undefined) {
        style.width = typeof width === 'number' ? `${width}px` : width
      }
      if (height !== undefined) {
        style.height = typeof height === 'number' ? `${height}px` : height
      }

      if (currentStatus) {
        if (currentStatus.bgColor) {
          style.backgroundColor = currentStatus.bgColor
        }
        if (currentStatus.backgroundImage) {
          style.backgroundImage = `url('${currentStatus.backgroundImage}')`
        }
        if (currentStatus.textColor) {
          style.color = currentStatus.textColor
        }
      }

      // 添加闪烁动画
      if (isBlinking) {
        style.animation = 'blink-animation 0.5s ease-in-out 3'
      }

      return style
    }, [currentStatus, width, height, isBlinking])

    return (
      <div
        ref={ref}
        className={cn(
          "status-component",
          isBlinking && "status-blink",
          className
        )}
        style={containerStyle}
        {...props}
      >
        {currentStatus?.text || (value !== undefined ? String(value) : '-')}
      </div>
    )
  }
)

Status.displayName = "Status"

export { Status }

import * as React from "react"
import { cn } from "@/lib/utils"
import "./svg.css"

export interface SvgEditorProps {
  className?: string
  /**
   * SVG 内容字符串
   */
  initialSvg?: string
  /**
   * 宽度
   */
  width?: number | string
  /**
   * 高度
   */
  height?: number | string
}

const SvgEditor = React.forwardRef<HTMLDivElement, SvgEditorProps>(
  (
    {
      className,
      initialSvg = "",
      width = "100%",
      height = "100%",
      ...props
    },
    ref
  ) => {
    // 内部 SVG 内容状态
    const [currentSvg, setCurrentSvg] = React.useState(initialSvg)

    // 当 initialSvg prop 变化时更新内部状态
    React.useEffect(() => {
      if (initialSvg && initialSvg !== currentSvg) {
        setCurrentSvg(initialSvg)
      }
    }, [initialSvg])

    // 解析 SVG 字符串，提取实际的 SVG 内容
    const getSvgContent = (svgString: string) => {
      if (!svgString) return ""

      // 如果字符串包含 <svg> 标签，提取它
      const svgMatch = svgString.match(/<svg[^>]*>([\s\S]*?)<\/svg>/i)
      if (svgMatch) {
        return svgMatch[0]
      }

      // 否则返回原字符串
      return svgString
    }

    const svgContent = getSvgContent(currentSvg || "")

    return (
      <div
        ref={ref}
        className={cn("svg-editor", "svg-editor-view-only", className)}
        style={{ width, height }}
        {...props}
      >
        {svgContent ? (
          <div
            className="svg-editor-view-only-content"
            dangerouslySetInnerHTML={{ __html: svgContent }}
          />
        ) : (
          <div className="svg-editor-empty">
            <p>暂无 SVG 内容</p>
          </div>
        )}
      </div>
    )
  }
)

