  // 单选实现
  return (
    <div className="w-full" style={{ width, ...style }} {...restProps}>
      <Select
        value={displayValue}
        onValueChange={handleChange}
        disabled={loading}
      >
        <SelectTrigger className="w-full">
          <SelectValue placeholder={placeholder} />
        </SelectTrigger>
        <SelectContent>
          {options.map((option) => (
            <SelectItem key={option.value} value={option.value}>
              {option.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  )
}

