import * as React from "react"
import { ChevronDown, MinusCircle, PlusCircle } from "lucide-react"
import { cn } from "@/lib/utils"
import { createAPI } from '@airiot/client'

export type PtzAction =
  | "up"
  | "down"
  | "left"
  | "right"
  | "upLeft"
  | "upRight"
  | "downLeft"
  | "downRight"
  | "zoomIn"
  | "zoomOut"

export type ButtonWidgetControlMode = "click" | "hold"

export interface ButtonWidgetProps extends React.HTMLAttributes<HTMLDivElement> {
  size?: number | string
  bg?: string
  btnColor?: string
  controlMode?: ButtonWidgetControlMode
  disable?: boolean
  tableData?: Record<string, any>
  table?: Record<string, any>
  buttonType?: 'hk' | 'ez'
  onActionClick?: (action: PtzAction) => void
  onActionStart?: (action: PtzAction) => void
  onActionEnd?: (action: PtzAction) => void
  /**
   * 单元格唯一标识
   */
  cellKey?: string
}

type ControlItem = {
  action: PtzAction
  label: string
  placement: React.CSSProperties
  icon: "arrow" | "plus" | "minus"
  rotateDeg?: number
}

const DEFAULT_SIZE = 220

const ButtonWidget = React.forwardRef<HTMLDivElement, ButtonWidgetProps>(
  (
    {
      className,
      size = DEFAULT_SIZE,
      bg = "#222641",
      btnColor = "#757c99",
      controlMode = "hold",
      disable = false,
      tableData,
      table,
      buttonType = 'hk',
      onActionClick,
      onActionStart,
      onActionEnd,
      ...props
    },
    ref
  ) => {
    const resolvedTableData = React.useMemo(() => {
      if (tableData?._table && !tableData?.table) {
        return { ...tableData, table: { id: tableData?._table } }
      }
      return tableData
    }, [tableData])

    const fetchTableSchema = React.useCallback(async (tableId: string) => {
      const api = createAPI({ resource: 'core/t/schema' })
      return api.get(tableId)
    }, [])

    const sendCommand = React.useCallback(async (command: any, controlType?: 'down' | 'up') => {
      if (!resolvedTableData?.id) return
      const tableId = resolvedTableData?.table?.id || table?.id
      if (!tableId) return

      const { json } = await fetchTableSchema(tableId)
      const groupId = json?.device?.groupId

      if (controlType && groupId) {
        let urlType = ''
        if (controlType === 'down') urlType = 'ptzStart'
        if (controlType === 'up') urlType = 'ptzStop'
        const api = createAPI({ resource: 'driver/driver/httpProxy' })
        await api.fetch(`?type=${urlType}&groupId=${groupId}`, {
          method: 'POST',
          body: JSON.stringify({ table: tableId, direction: command.id, id: resolvedTableData.id })
        })
        return
      }

      const api = createAPI({ resource: 'driver/driver/command' })
      await api.fetch('', {
        method: 'POST',
        body: JSON.stringify({
          ...command,
          title: command.name,
          tableData: resolvedTableData.id,
          table: tableId
        })
      })
    }, [resolvedTableData, table, fetchTableSchema])

    const handleCommand = React.useCallback(async (action: PtzAction, controlType?: 'down' | 'up') => {
      if (!resolvedTableData?.id) return
      const tableId = resolvedTableData?.table?.id || table?.id
      if (!tableId) return
      const { json } = await fetchTableSchema(tableId)
      const commands = json?.device?.commands || []

      const command = commands.find((item: any) => item.name === action)
      if (command) {
        await sendCommand(command, controlType)
      }
    }, [resolvedTableData, table, fetchTableSchema, sendCommand])
    const containerSize = React.useMemo<React.CSSProperties>(() => {
      if (typeof size === "number") {
        return { width: size, height: size }
      }
      return { width: size, height: size }
    }, [size])

    const items = React.useMemo<ControlItem[]>(() => {
      const inner = "9%"
      const corner = "19%"
      return [
        {
          action: "up",
          label: "上",
          icon: "arrow",
          rotateDeg: 180,
          placement: { top: inner, left: "50%", transform: "translate(-50%, 0)" },
        },
        {
          action: "upLeft",
          label: "左上",
          icon: "arrow",
          rotateDeg: 135,
          placement: { top: corner, left: corner },
        },
        {
          action: "left",
          label: "左",
          icon: "arrow",
          rotateDeg: 90,
          placement: { top: "50%", left: inner, transform: "translate(0, -50%)" },
        },
        {
          action: "downRight",
          label: "右下",
          icon: "arrow",
          rotateDeg: -45,
          placement: { bottom: corner, right: corner },
        },
        {
          action: "down",
          label: "下",
          icon: "arrow",
          rotateDeg: 0,
          placement: { bottom: inner, left: "50%", transform: "translate(-50%, 0)" },
        },
        {
          action: "right",
          label: "右",
          icon: "arrow",
          rotateDeg: -90,
          placement: { top: "50%", right: inner, transform: "translate(0, -50%)" },
        },
        {
          action: "upRight",
          label: "右上",
          icon: "arrow",
          rotateDeg: 225,
          placement: { top: corner, right: corner },
        },
        {
          action: "downLeft",
          label: "左下",
          icon: "arrow",
          rotateDeg: 45,
          placement: { bottom: corner, left: corner },
        },
        {
          action: "zoomIn",
          label: "放大",
          icon: "plus",
          placement: {
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -110%)",
          },
        },
        {
          action: "zoomOut",
          label: "缩小",
          icon: "minus",
          placement: {
            top: "50%",
            left: "50%",
            transform: "translate(-50%, 10%)",
          },
        },
      ]
    }, [])

    const callStart = React.useCallback(
      (action: PtzAction) => {
        if (disable) return
        onActionStart?.(action)
        if (buttonType === 'hk') {
          handleCommand(action, 'down')
        }
      },
      [disable, onActionStart, handleCommand, buttonType]
    )

    const callEnd = React.useCallback(
      (action: PtzAction) => {
        if (disable) return
        onActionEnd?.(action)
        if (buttonType === 'hk') {
          handleCommand(action, 'up')
        }
      },
      [disable, onActionEnd, handleCommand, buttonType]
    )

    const callClick = React.useCallback(
      (action: PtzAction) => {
        if (disable) return
        onActionClick?.(action)
        if (buttonType !== 'hk') {
          handleCommand(action)
        }
      },
      [disable, onActionClick, handleCommand, buttonType]
    )

    const renderIcon = (item: ControlItem) => {
      if (item.icon === "plus") return <PlusCircle className="h-5 w-5" />
      if (item.icon === "minus") return <MinusCircle className="h-5 w-5" />
      return (
        <ChevronDown
          className="h-5 w-5"
          style={
            item.rotateDeg !== undefined
              ? { transform: `rotate(${item.rotateDeg}deg)` }
              : undefined
          }
        />
      )
    }

    const bindHoldEvents = (action: PtzAction) => {
      return {
        onPointerDown: (e: React.PointerEvent<HTMLButtonElement>) => {
          if (disable) return
          e.preventDefault()
          e.currentTarget.setPointerCapture?.(e.pointerId)
          callStart(action)
        },
        onPointerUp: (e: React.PointerEvent<HTMLButtonElement>) => {
          if (disable) return
          e.preventDefault()
          callEnd(action)
        },
        onPointerLeave: () => {
          callEnd(action)
        },
        onPointerCancel: () => {
          callEnd(action)
        },
      }
    }

    return (
      <div
        ref={ref}
        className={cn("w-full h-full flex items-center justify-center", className)}
        {...props}
      >
        <div
          className={cn(
            "relative rounded-full select-none",
            disable && "opacity-50 pointer-events-none"
          )}
          style={{ ...containerSize, background: bg }}
        >
          <div
            className="absolute inset-[14%] rounded-full"
            style={{ background: "rgba(0,0,0,0.18)" }}
          />
          <div
            className="absolute inset-[34%] rounded-full"
            style={{ background: "rgba(0,0,0,0.25)" }}
          />

          {items.map((item) => {
            const isClickMode = controlMode === "click"
            const baseEvents = isClickMode
              ? {
                  onClick: (e: React.MouseEvent<HTMLButtonElement>) => {
                    e.preventDefault()
                    callClick(item.action)
                  },
                }
              : bindHoldEvents(item.action)

            return (
              <button
                key={item.action}
                type="button"
                title={item.label}
                aria-label={item.label}
                className={cn(
                  "absolute grid place-items-center rounded-full",
                  "h-10 w-10",
                  "bg-transparent hover:bg-white/10 active:bg-white/20",
                  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                  "transition-colors"
                )}
                style={{ ...item.placement, color: btnColor }}
                {...baseEvents}
              >
                {renderIcon(item)}
              </button>
            )
          })}
        </div>
      </div>
    )
  }
)

ButtonWidget.displayName = "ButtonWidget"

export { ButtonWidget }

import * as React from "react"
import { WebControl } from "./web-control.esm.min.js"

// 初始化参数接口
export interface InitConfig {
  appkey?: string
  ip?: string
  port?: number
  secret?: string
  enableHTTPS?: number
  language?: string
  layout?: string
  playMode?: number
  reconnectDuration?: number
  reconnectTimes?: number
  showSmart?: number
  showToolbar?: number
  toolBarButtonIDs?: string
  snapDir?: string
  videoDir?: string
}

// 节点接口
export interface Node {
  id: string
  [key: string]: any
}

// 预览配置
export interface PlayConfig {
  streamMode?: string
}

// 回放配置
export interface PlayBackConfig {
  startTimeStamp?: string
  endTimeStamp?: string
  playTimeStamp?: string
  recordLocation?: string
}

// 组件属性
export interface IscVideoProps {
  /** 编辑模式 */
  editMode?: boolean
  /** 单元格键 */
  cellKey?: string
  /** 节点列表 */
  nodes?: Node[]
  /** 初始化配置 */
  initConfig?: InitConfig
  /** 预览配置 */
  playConfig?: PlayConfig
  /** 回放配置 */
  playBackConfig?: PlayBackConfig
}

// 获取初始化参数
const getInitArgument = (initConfig?: InitConfig): any => {
  const defaultInit = {
    appkey: "",
    ip: "",
    port: 443,
    secret: "",
    enableHTTPS: 1,
    language: "zh_CN",
    layout: "2x2",
    playMode: 0,
    reconnectDuration: 5,
    reconnectTimes: 5,
    showSmart: 0,
    showToolbar: 1,
    toolBarButtonIDs: "2048,2049,2050,2304,2306,2305,2307,2308,2309,4096,4608,4097,4099,4098,4609,4100",
    snapDir: "D:/snap",
    videoDir: "D:/video",
  }
  return { ...defaultInit, ...initConfig }
}

// 更新播放/回放
const update = async ({
  oWebControl,
  nodes = [],
  initConfig,
  playConfig,
  playBackConfig,
}: {
  oWebControl: any
  nodes: Node[]
  initConfig?: InitConfig
  playConfig?: PlayConfig
  playBackConfig?: PlayBackConfig
}) => {
  const initArgument = getInitArgument(initConfig)
  if (initArgument?.playMode === 0) {
    // 停止所有预览
    await oWebControl.JS_RequestInterface({
      argument: {},
      funcName: "stopAllPreview",
    })
    // 批量播放
    await oWebControl.JS_RequestInterface({
      argument: {
        list: nodes.map((node, index) => ({
          authUuid: "",
          cameraIndexCode: node?.id,
          ezvizDirect: 0,
          gpuMode: 0,
          streamMode: parseInt(playConfig?.streamMode || "0"),
          transMode: 1,
          wndId: index + 1,
        })),
      },
      funcName: "startMultiPreviewByCameraIndexCode",
    })
    console.log("批量播放")
  } else if (initArgument?.playMode === 1) {
    // 停止所有回放
    await oWebControl.JS_RequestInterface({
      argument: {},
      funcName: "stopAllPlayback",
    })
    // 批量回放
    await oWebControl.JS_RequestInterface({
      argument: {
        list: nodes.map((node, index) => ({
          authUuid: "",
          cameraIndexCode: node?.id,
          endTimeStamp: Math.floor(new Date(playBackConfig?.endTimeStamp || Date.now()).getTime() / 1000),
          ezvizDirect: 0,
          gpuMode: 0,
          playTimeStamp: Math.floor(new Date(playBackConfig?.playTimeStamp || Date.now()).getTime() / 1000),
          recordLocation: parseInt(playBackConfig?.recordLocation || "0"),
          startTimeStamp: Math.floor(new Date(playBackConfig?.startTimeStamp || Date.now()).getTime() / 1000),
          transMode: 1,
          wndId: index + 1,
        })),
      },
      funcName: "startMultiPlaybackByCameraIndexCode",
    })
    console.log("批量回放")
  }
}

// 启动插件
const start = ({
  nodes = [],
  initConfig,
  playConfig,
  playBackConfig,
  setInit,
  setActiveWin,
  instanceId,
}: {
  nodes: Node[]
  initConfig?: InitConfig
  playConfig?: PlayConfig
  playBackConfig?: PlayBackConfig
  setInit: (init: boolean) => void
  setActiveWin: (winId: number) => void
  instanceId: string
}) => {
  // 检查 WebControl 是否可用（已通过导入）
  const oWebControl = new WebControl({
    szPluginContainer: `iscPlayWnd-${instanceId}`,
    iServicePortStart: 15900,
    iServicePortEnd: 15900,
    szClassId: "23BF3B0A-2C56-4D97-9C03-0CB103AA8F11",
    cbConnectSuccess: async () => {
      console.log("cbConnectSuccess")
      // 启动服务
      await oWebControl.JS_StartService("window", {
        dllPath: "./VideoPluginConnect.dll",
      })
      console.log("启动服务")
      // 创建窗口
      const container = document.querySelector(`#iscPlayWnd-${instanceId}`)
      if (!container) return
      const { clientWidth, clientHeight } = container as HTMLElement
      await oWebControl.JS_CreateWnd(`iscPlayWnd-${instanceId}`, clientWidth, clientHeight)
      console.log("创建窗口")
      // 获取公钥
      await oWebControl.JS_RequestInterface({
        funcName: "getRSAPubKey",
        argument: JSON.stringify({
          keyLength: 1024,
        }),
      })
      console.log("获取公钥")
      // 初始化
      const initArgument = getInitArgument(initConfig)
      await oWebControl.JS_RequestInterface({
        argument: initArgument,
        funcName: "init",
      })
      setInit(true)
      console.log("初始化")
      update({ oWebControl, nodes, initConfig, playConfig, playBackConfig })
      // 设置窗口大小
      oWebControl.JS_Resize(clientWidth, clientHeight)
      // 监听消息
      oWebControl.JS_SetWindowControlCallback({
        cbIntegrationCallBack({ responseMsg }: any) {
          if (responseMsg?.type === 1) {
            setActiveWin(responseMsg?.msg?.wndId)
          } else if (responseMsg?.type === 6) {
            setActiveWin(1)
          }
        },
      })
    },
    cbConnectError: () => {
      console.log("cbConnectError")
    },
    cbConnectClose: (bNormalClose: boolean) => {
      console.log("cbConnectClose", bNormalClose)
    },
  })
  return oWebControl
}

// 停止插件
const stop = async ({
  oWebControl,
  setInit,
}: {
  oWebControl: any
  setInit: (init: boolean) => void
}) => {
  if (oWebControl) {
    try {
      await oWebControl.JS_RequestInterface({
        funcName: "uninit",
      })
      if (oWebControl.JS_HideWnd) {
        oWebControl.JS_HideWnd()
      }
      await oWebControl.JS_DestroyWnd()
      console.log("销毁成功")
      setInit(false)
    } catch (error) {
      console.error("停止插件失败", error)
    }
  }
}

// 播放单个视频
const play = async ({
  oWebControl,
  wndId,
  nodeId,
  streamMode,
}: {
  oWebControl: any
  wndId: number
  nodeId: string
  streamMode?: string
}) => {
  await oWebControl.JS_RequestInterface({
    argument: {
      authUuid: "",
      cameraIndexCode: nodeId,
      ezvizDirect: 0,
      gpuMode: 0,
      streamMode: parseInt(streamMode || "0"),
      transMode: 1,
      wndId,
    },
    funcName: "startPreview",
  })
}

// 主组件
const IscVideo: React.FC<IscVideoProps> = ({
  editMode = false,
  cellKey,
  nodes = [],
  initConfig,
  playConfig,
  playBackConfig,
}) => {
  const oWebControlRef = React.useRef<any>(null)
  const [instanceId] = React.useState(() => Math.random().toString(36).substr(2, 9))
  const [init, setInit] = React.useState(false)
  const [activeWin, setActiveWin] = React.useState(1)

  // 注册播放函数（原逻辑使用 xadmin cell.functions.set，这里简化）
  React.useEffect(() => {
    if (cellKey) {
      // 可以在此处将播放函数暴露给父组件，但暂时留空
      console.log("注册播放函数到 cellKey:", cellKey)
    }
  }, [cellKey, activeWin, playConfig?.streamMode])

  // 启动/停止插件
  React.useEffect(() => {
    if (!editMode) {
      try {
        oWebControlRef.current = start({
          nodes,
          initConfig,
          playConfig,
          playBackConfig,
          setInit,
          setActiveWin,
          instanceId,
        })
        console.log(oWebControlRef.current, "oWebControlRef.current")
      } catch (error) {
        console.error("启动插件失败", error)
      }
    }
    return () => {
      try {
        setTimeout(() => {
          if (oWebControlRef.current) {
            stop({ oWebControl: oWebControlRef.current, setInit })
          }
        }, 500)
      } catch (error) {
        console.error("停止插件失败", error)
      }
    }
  }, [])

  // 节点变化时更新
  React.useEffect(() => {
    if (!editMode && init && oWebControlRef.current) {
      try {
        update({
          oWebControl: oWebControlRef.current,
          nodes,
          initConfig,
          playConfig,
          playBackConfig,
        })
      } catch (error) {
        console.error("更新播放失败", error)
      }
    }
  }, [JSON.stringify(nodes)])

  if (editMode) {
    return (
      <div
        id={`iscPlayWnd-${instanceId}`}
        style={{
          width: "100%",
          height: "100%",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          border: "1px dashed #ccc",
          borderRadius: "4px",
          backgroundColor: "#f9f9f9",
        }}
      >
        <div style={{ textAlign: "center", color: "#666" }}>
          <div>ISC 视频组件</div>
          <div style={{ fontSize: "12px", marginTop: "8px" }}>请预览查看视频显示效果</div>
        </div>
      </div>
    )
  }

  return (
    <div
      id={`iscPlayWnd-${instanceId}`}
      style={{ width: "100%", height: "100%", minHeight: "300px" }}
    />
  )
}

