interface ExportActionContentProps {
  itemId: string
  format?: 'json' | 'csv' | 'excel'
}

const ExportActionContent: React.FC<ExportActionContentProps> = ({ itemId, format = 'json' }) => {
  const { data, loading } = useModelGet({ id: itemId })

  const handleExport = () => {
    let content = ''
    let filename = `export_${itemId}`
    let mimeType = 'text/plain'

    switch (format) {
      case 'json':
        content = JSON.stringify(data, null, 2)
        filename += '.json'
        mimeType = 'application/json'
        break
      case 'csv':
        // Simple CSV export
        if (data && typeof data === 'object') {
          const headers = Object.keys(data)
          const values = Object.values(data).map(v =>
            typeof v === 'object' ? JSON.stringify(v) : String(v)
          )
          content = [headers.join(','), values.join(',')].join('\n')
        }
        filename += '.csv'
        mimeType = 'text/csv'
        break
      case 'excel':
        // For excel, you would typically use a library like xlsx
        content = JSON.stringify(data, null, 2)
        filename += '.json'
        break
    }

    const blob = new Blob([content], { type: mimeType })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    a.click()
    URL.revokeObjectURL(url)
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>导出数据</DialogTitle>
      </DialogHeader>
      {loading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-6 w-6 animate-spin text-primary" />
        </div>
      ) : (
        <ScrollArea className="max-h-[50vh]">
          <div className="space-y-4 pr-4">
            <p className="text-sm text-slate-600">
              选择导出格式：
            </p>
            <div className="grid gap-2">
              <Button
                variant="outline"
                className="justify-start"
                onClick={() => handleExport()}
              >
                JSON 格式
              </Button>
              <Button
                variant="outline"
                className="justify-start"
                onClick={() => handleExport()}
              >
                CSV 格式
              </Button>
            </div>
          </div>
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      )}

      <DialogFooter>
        <DialogClose asChild>
          <Button variant="outline">关闭</Button>
        </DialogClose>
      </DialogFooter>
    </>
  )
}

