import React, { cloneElement, useEffect, useMemo, useState } from 'react';
import { useModelList, useModel, useModelState, type ModelSchema } from '@airiot/client'
import { DataGrid } from '@/components/reui/data-grid/data-grid';
import { DataGridColumnHeader } from '@/components/reui/data-grid/data-grid-column-header';
import {
  DataGridTable,
  DataGridTableRowSelect,
  DataGridTableRowSelectAll,
} from '@/components/reui/data-grid/data-grid-table';
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area';
import {
  type ColumnDef, type TableOptions, type CellContext, type SortingState, type RowSelectionState,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
  createColumnHelper,
} from '@tanstack/react-table';
import { cn } from '@/lib/utils';
import { tableConverter } from '@/registry/lib/view-table-converter'

interface IData {
  id: string;
  [key: string]: any;
}

export interface TableLayoutProps {
  border?: boolean;
  dense?: boolean;
  cellBorder?: boolean;
  rowBorder?: boolean;
  rowRounded?: boolean;
  stripped?: boolean;
  headerBackground?: boolean;
  headerBorder?: boolean;
  headerSticky?: boolean;
  width?: 'auto' | 'fixed';
  layout?: 'auto' | 'fixed';
  columnsVisibility?: boolean;
  columnsResizable?: boolean;
  columnsPinnable?: boolean;
  columnsMovable?: boolean;
  columnsDraggable?: boolean;
  rowsDraggable?: boolean;
}

const getFieldProp = (model: ModelSchema | null | undefined, field: string): any => {
  if (!model) return undefined
  return field.split('.').reduce((obj: any, f: string) => {
    return obj && obj.properties && obj.properties[f]
  }, model)
}

const DataCell = ({ children, schema, tableSchema, ...restProps }:
  {
    children?: React.ReactNode | ((props: any) => React.ReactNode), [key: string]: any
  }) =>
  ({ getValue, row, column }: CellContext<IData, any>) => {

    const baseSchema = schema || column.columnDef?.field

    const childrenProps = {
      ...restProps,
      value: getValue(),
      item: row.original,
      schema: { ...baseSchema, ...tableSchema },
      tableSchema,
    }

    const FieldComponent = tableConverter(schema, tableSchema)

    return (
      children ? (typeof children === 'function' ? children(childrenProps) : cloneElement(children as React.ReactElement<any>, childrenProps)) : (
        <FieldComponent {...childrenProps} />
      )
    )
  }

export const DataTable = ({
  data,
  columns = [],
  className,
  tableLayout = {},
  tableOptions = {},
  gridOptions = {},
  children
}: {
  data: IData[],
  className?: string,
  tableLayout?: TableLayoutProps,
  tableOptions?: Omit<TableOptions<IData>, 'data' | 'columns' | 'getCoreRowModel'>,
  columns?: ColumnDef<IData>[]
  gridOptions: Omit<React.ComponentProps<typeof DataGrid>, 'table' | 'recordCount' | 'tableLayout'>
  children?: React.ReactElement[] | undefined
}) => {
  const { withColumns, getColumns } = useTableContainer(children);
  const defColumns: ColumnDef<IData>[] = getColumns();
  const columnsFinal = [] as ColumnDef<IData>[];

  columns.forEach(column => {
    const defColumn = defColumns.find(col => col.id === column.id);
    if (defColumn) {
      Object.assign(column, defColumn)
      defColumns.splice(defColumns.indexOf(defColumn), 1)
    }
    columnsFinal.push(column);
  })
  defColumns.forEach(col => {
    columnsFinal.push(col);
  })

  const table = useReactTable({
    columns: columnsFinal,
    data: data,
    getRowId: (row: IData) => row.id,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    columnResizeMode: 'onChange',
    ...tableOptions,
  });

  // 合并默认 tableLayout 和传入的 tableLayout
  const defaultTableLayout: TableLayoutProps = {
    border: true,
    columnsResizable: true,
    columnsPinnable: true,
    headerSticky: true,
    rowBorder: true,
    cellBorder: false,
    headerBorder: true,
    width: 'fixed'
  }

  const mergedTableLayout = { ...defaultTableLayout, ...tableLayout }

  return withColumns(
    <DataGrid table={table} recordCount={data?.length || 0}
      tableLayout={mergedTableLayout}
      {...gridOptions}>
      <div data-slot="data-grid" className={cn('w-full', mergedTableLayout.border && 'border border-border rounded-lg', className)}>
        <ScrollArea>
          <DataGridTable />
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      </div>
    </DataGrid>
  );
}

export function ViewDataTable({
  className,
  tableLayout = {},
  tableOptions = {},
  gridOptions = {},
  children
}: {
  className?: string,
  tableLayout?: TableLayoutProps,
  tableOptions?: Omit<TableOptions<IData>, 'data' | 'columns' | 'getCoreRowModel'>,
  columns?: ColumnDef<IData>[]
  gridOptions?: Omit<React.ComponentProps<typeof DataGrid>, 'table' | 'recordCount' | 'tableLayout'>
  children?: React.ReactElement[] | undefined
}) {
  const { items, loading, fields } = useModelList()
  const { model, atoms } = useModel()

  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});
  const [selected, setSelected] = useModelState<{ id: string }[]>(atoms.selected)

  const [order, setOrder] = useModelState(atoms.order)
  const [sorting, setSorting] = useState<SortingState>([])

  const columnHelper = createColumnHelper<IData>()
  const columns: ColumnDef<IData>[] = []

  fields.forEach((tableSchema) => {
    const fieldName = tableSchema.key
    const baseSchema = getFieldProp(model, fieldName)
    const field = { ...baseSchema, ...tableSchema }
    if (!field) return
    const column: ColumnDef<IData> = columnHelper.accessor(fieldName, {
      id: fieldName,
      field,
      size: field.width || undefined,
      fixed: field.tableFixed,
      enableSorting: field.canOrder,
      header: ({ column }) => {
        return <DataGridColumnHeader title={field.title || fieldName} column={column} />
      },
      cell: DataCell({
        name: fieldName,
        schema: baseSchema,
        tableSchema,
        inList: true,
        type: field.type as string,
        ...field.column
      }),
      ...field.column
    })

    if (field.level2) {
      const lastColumn = columns[columns.length - 1] as any
      if (lastColumn && lastColumn.columns !== undefined &&
        lastColumn.header == field.level2) {
        lastColumn.columns.push(column)
      } else {
        columns.push({
          header: field.level2,
          columns: [column]
        })
      }
    } else {
      columns.push(column)
    }
  })

  // 配置行选择
  const onRowSelectionChange = (handler: (state: RowSelectionState) => RowSelectionState) => {
    const newSelection = handler(rowSelection)
    setSelected(items.filter(item => newSelection[item.id]));
  }

  useEffect(() => {
    setRowSelection(selected.reduce((obj: Record<string, boolean>, item: any) => {
      obj[item.id] = true;
      return obj;
    }, {}));
  }, [selected]);

  columns.unshift({
    accessorKey: 'id',
    header: () => <DataGridTableRowSelectAll />,
    cell: ({ row }) => <DataGridTableRowSelect row={row} />,
    enableSorting: false,
    enableResizing: false,
    size: 35,
    meta: {
      headerClassName: '',
      cellClassName: '',
    },
  })

  // 配置排序
  const onSortingChange = (handler: (state: SortingState) => SortingState) => {
    const newSorting = handler(sorting)
    // 转换为 order 格式
    const newOrder: Record<string, 'asc' | 'desc'> = {}
    newSorting.forEach(sort => {
      newOrder[sort.id] = sort.desc ? 'desc' : 'asc'
    })
    // 更新模型状态
    setOrder(newOrder)
  }

  useEffect(() => {
    setSorting(Object.keys(order || {}).map(key => ({
      id: key,
      desc: order ? order[key]?.toLowerCase() === 'desc' : false,
      asc: order ? order[key]?.toLowerCase() === 'asc' : false
    })));
  }, [order]);

  const tableProps = model.dataTableProps ? (
    typeof model.dataTableProps == 'function' ?
      model.dataTableProps(columns, items) : model.dataTableProps
  ) : {}

  return <DataTable
    data={items as IData[]}
    columns={columns}
    className={className}
    tableLayout={tableLayout}
    gridOptions={{
      loadingMode: 'spinner',
      loadingMessage: '数据加载中...',
      emptyMessage: '暂无数据',
      ...gridOptions,
      isLoading: loading
    }}
    tableOptions={{
      ...tableProps,
      ...tableOptions,
      initialState: {
        ...tableOptions.initialState,
        columnPinning: {
          right: ['__actions__'],
        },
      },
      // 添加行选择配置
      ...({ onRowSelectionChange, enableRowSelection: true, }),
      // 添加排序配置
      state: {
        ...(tableOptions.state || {}),
        sorting,
        rowSelection
      },
      onSortingChange
    }}
  >{children}</DataTable>;
}

// TableColumn 组件 - 用于定义和配置列
interface TableColumnProps {
  name: string;
  title?: string;
  width?: number;
  fixed?: boolean | 'left' | 'right';
  header?: React.ReactNode;
  cell?: React.ReactNode;
  type?: string;
  level2?: string;
  children?: React.ReactNode | ((props: any) => React.ReactNode);
  [key: string]: any;
}

interface ColumnContextValue {
  columns: Map<string, ColumnDef<IData>>;
  setColumn: (name: string, column: ColumnDef<IData>) => void;
  getColumn: (name: string) => ColumnDef<IData> | undefined;
  getColumns: () => ColumnDef<IData>[];
}

const ColumnContext = React.createContext<ColumnContextValue | null>(null);

const useTableContainer = (children: React.ReactElement[] | undefined) => {
  const columns = React.useRef<Map<string, ColumnDef<IData>>>(new Map());
  const [inited, setInited] = React.useState<boolean>(false);

  // 设置列
  const setColumn = (name: string, column: ColumnDef<IData>) => {
    columns.current.set(name, column);
  };

  // 获取单个列
  const getColumn = (name: string): ColumnDef<IData> | undefined => {
    return columns.current.get(name);
  };

  // 获取所有列（按定义顺序）
  const getColumns = (): ColumnDef<IData>[] => {
    return Array.from(columns.current.values());
  };

  const contextValue: ColumnContextValue = {
    columns: columns.current,
    setColumn,
    getColumn,
    getColumns,
  };

  React.useEffect(() => {
    if (!inited)
      setInited(true);
  }, []);

  const withColumns = React.useCallback((table: React.ReactElement) => (
    <ColumnContext.Provider value={contextValue}>
      {useMemo(() => children, [])}
      {inited && table}
    </ColumnContext.Provider>
  ), [children, contextValue, inited])

  return { withColumns, getColumns };
}

export const TableColumn: React.FC<TableColumnProps> = ({
  name,
  title,
  width,
  fixed,
  header,
  cell,
  level2,
  children,
  ...columnProps
}) => {
  const columnContext = React.useContext(ColumnContext);

  if (!columnContext) {
    console.warn('TableColumn must be used within DataTableContainer');
    return null;
  }

  React.useEffect(() => {
    const columnDef: ColumnDef<IData> = {
      id: name,
      accessorKey: name,
      fixed: fixed,
      header: header ? header as any : (({ column }) => <DataGridColumnHeader title={title || name} column={column as any} />),
      cell: cell ? cell as any : DataCell({ children, ...columnProps }),
      size: width as number | undefined,
      ...columnProps
    };

    columnContext.setColumn(name, columnDef);
  }, [name, title, children, width, fixed, header, cell, level2, columnContext, columnProps]);

  return null;
};

export default ViewDataTable;

/**
 * 将旧版本的 schema 格式转换为新的分离格式
 */

// 类型定义
interface OldSchemaField {
  type: string;
  key: string;
  title: string;
  config: string;
  [key: string]: any;
}

interface OldSchema {
  type: string;
  name?: string;
  title: string;
  key: string;
  properties: Record<string, OldSchemaField>;
  required?: string[];
  form?: string[];
  listFields?: string[];
}

interface NewSchemaField {
  type?: string;
  title?: string;
  key?: string;
  controlType?: string;
  [key: string]: any;
}

interface SchemaItem {
  key: string;
  [key: string]: any;
}

interface NewSchema {
  schema: {
    type: string;
    title: string;
    key: string;
    properties: Record<string, NewSchemaField>;
    required?: string[];
  };
  tableSchema: SchemaItem[];
  formSchema: SchemaItem[];
  filterSchema: SchemaItem[];
}

// config 到 controlType 的基础映射
const configToControlType: Record<string, string> = {
  '文本': 'text',
  '数字': 'number',
  '选择器': 'select',
  '时间': 'date',
  '日期范围': 'date-range',
  '时间2': 'time',
  '富文本': 'rich-text',
  '布尔值': 'boolean',
  '查找引用': 'reference',
  '表格': 'editable-table',
  '附件': 'upload',
  '附件组': 'upload',
  '区域': 'area',
  '星级评价': 'rate',
  '定位': 'map',
  '链接': 'link',
  '公式': 'formula',
  '编号': 'serial-number',
  '用户': 'user-role',
  '字节数组': 'bytes-array',
  '关联字段': 'relate-plus',
};

// 基础 schema 需要保留的属性
const baseSchemaProps = new Set<string>([
  'type', 'title', 'minLength', 'maxLength',
  'textContent', 'languageType', 'defaultVal', 'description', 'unique',
  'jsLogic', 'need', 'dbType', 'bitNum', 'decimal', 'min', 'max', 'unit', 'enum',
  'enumNames', // enum_title 转换后
  'metricStore', 'properties', 'items',
  'relate', 'showField', 'relateShowFields', 'insideFilter',
  'searchRelate', 'searchCondition', 'computeMethod', 'sort', 'numberLimit', 'numberFormat',
  'maxCount', 'minCount',
  'styleType', 'accept', 'uploadPosition', 'mediaDelete', 'autoZip', 'size', 'folderType', 'folder', 'watermark', 'base64', 'autoName', 'addToken',
  'maxUploadNum', 'pattern', 'serialRules', 'relateTo', 'userType',
  'controlType', // 新增
]);

// tableSchema 需要保留的属性
const tableSchemaProps = new Set<string>([
  'listFields', 'canOrder', 'tableFixed', 'NullShow', 'recordDetail',
  'previewSize', 'listShow', 'showNum', 'lngLat', 'positionName',
]);

// formSchema 需要保留的属性
const formSchemaProps = new Set<string>([
  'afterNow', 'timeFormat', 'allowSelectOld', 'allowAdd',
  'highTableFields', 'btnText', 'displayForm', 'cardLayout', 'showPagination', 'uniqueRow',
  'uniqueFields', 'fieldRules', 'createAddBtn', 'editAddBtn', 'createDelBtn', 'editDelBtn',
  'onlyCamera', 'canDownload', 'areaType', 'count', 'showType', 'canEdit',
  'linkType', 'placeholder', 'checkedChildren', 'unCheckedChildren', 'manualChange',
  'selectType', 'selectFace', 'treeMark', 'recordSelectType',
  'dateFormat', 'dateType', 'format', 'filedFormat', 'filterMode',
  'width', 'height', 'sort', 'widthInForm',
]);

// filterSchema 需要保留的属性
const filterSchemaProps = new Set<string>([
  'filterFields',
  'filterFormat',
]);

/**
 * 主转换函数
 * @param oldSchema - 旧版本的 schema 对象
 * @returns 新格式的 schema 对象
 */
function transformSchema(oldSchema: OldSchema): NewSchema {
  const result: NewSchema = {
    schema: {
      type: 'object',
      title: oldSchema?.title || oldSchema.title || '',
      key: oldSchema?.key || oldSchema.key || '',
      properties: {},
    },
    tableSchema: [],
    formSchema: [],
    filterSchema: [],
  };

  // 保存原 schema 的 required
  if (oldSchema?.required) {
    result.schema.required = oldSchema.required;
  }

  // 获取字段顺序配置
  const formOrder = oldSchema?.form || [];
  const listFieldsOrder = oldSchema?.listFields || [];

  // 遍历所有属性进行转换
  Object.entries(oldSchema?.properties || {}).forEach(([key, fieldValue]) => {
    const baseField: NewSchemaField = {};
    const tableField: SchemaItem = { key };
    const formField: SchemaItem = { key };
    const filterField: SchemaItem = { key };

    // 处理 controlType 转换
    let controlType = configToControlType[fieldValue.config];

    // 特殊规则: 文本
    if (fieldValue.config === '文本') {
      if (fieldValue.textType === 'input') {
        controlType = 'text';
      } else if (fieldValue.textType === 'textArea') {
        controlType = 'text-area';
      }
    }

    // 特殊规则: 选择器
    if (fieldValue.config === '选择器') {
      if (fieldValue.type === 'number') {
        controlType = 'select-number';
      } else if (fieldValue.type === 'string') {
        controlType = 'select-string';
      } else if (fieldValue.type === 'array') {
        if (fieldValue.items?.type === 'number') {
          controlType = 'select-array-number';
        } else if (fieldValue.items?.type === 'string') {
          controlType = 'select-array-string';
        }
      }
    }

    // 特殊规则: 关联字段
    if (fieldValue.config === '关联字段') {
      if (fieldValue.type === 'object') {
        controlType = 'relate';
      } else if (fieldValue.type === 'array') {
        controlType = 'relate-multiple';
      }
    }

    // 遍历字段的所有属性进行分类
    Object.entries(fieldValue).forEach(([propKey, propValue]) => {
      // 属性重命名映射
      const renamedKey: string = {
        'enum_title1': 'enumNames',
        'enum_title': 'enumNames',
        'enum1': 'enum',
        'tableFields': 'items',
      }[propKey] || propKey;

      // 跳过 config，已经转换为 controlType
      if (propKey === 'config') return;
      // 分配到对应的 schema
      if (baseSchemaProps.has(renamedKey)) {
        if (renamedKey == 'items') {
          const { schema, formSchema } = transformSchema(propValue)
          baseField[renamedKey] = { ...schema, formSchema }
        } else {
          baseField[renamedKey] = propValue;
        }
      } else if (tableSchemaProps.has(propKey)) {
        tableField[propKey] = propValue;
      } else if (formSchemaProps.has(propKey)) {
        formField[propKey] = propValue;
      } else if (filterSchemaProps.has(propKey)) {
        filterField[propKey] = propValue;
      }
    });

    // 设置 controlType
    if (controlType) {
      baseField.controlType = controlType;
    }

    // 保留 type, title, key
    baseField.type = fieldValue.type;
    baseField.title = fieldValue.title;
    baseField.key = fieldValue.key;

    // 添加到 schema.properties
    result.schema.properties[key] = baseField;

    // 如果字段在 form 中，添加到 formSchema
    if (formOrder.includes(key)) {
      // 只保留非空属性
      const cleanFormField = Object.fromEntries(
        Object.entries(formField).filter(([_, v]) => v !== undefined && v !== null)
      ) as SchemaItem;
      if (Object.keys(cleanFormField).length >= 1) {
        result.formSchema.push(cleanFormField);
      }
    }

    // 如果字段在 listFields 中，添加到 tableSchema
    if (listFieldsOrder.includes(key)) {
      // 只保留非空属性
      const cleanTableField = Object.fromEntries(
        Object.entries(tableField).filter(([_, v]) => v !== undefined && v !== null)
      ) as SchemaItem;
      if (Object.keys(cleanTableField).length >= 1) {
        result.tableSchema.push(cleanTableField);
      }
    }

    // 如果 filterFields 为 true，添加到 filterSchema
    if (fieldValue.filterFields === true) {
      // 移除 filterFields 和 key 属性（它们是标志位）
      const { filterFields, ...cleanFilterField } = filterField as any;
      // 只保留非空属性
      const finalFilterField = Object.fromEntries(
        Object.entries(cleanFilterField).filter(([_, v]) => v !== undefined && v !== null)
      ) as SchemaItem;
      result.filterSchema.push(finalFilterField);
    }
  });

  // 按 form 和 listFields 的顺序排序
  result.formSchema.sort((a, b) => formOrder.indexOf(a.fieldKey) - formOrder.indexOf(b.fieldKey));
  result.tableSchema.sort((a, b) => listFieldsOrder.indexOf(a.fieldKey) - listFieldsOrder.indexOf(b.fieldKey));

  return result;
}

export default transformSchema;

import React from 'react'
import { Download, Eye, Video, Music, FileText } from 'lucide-react'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from '@/components/ui/tooltip'
import { Button } from '@/components/ui/button'
import isArray from 'lodash/isArray'
import isString from 'lodash/isString'
import JSZip from 'jszip'
// @ts-ignore - file-saver doesn't have proper types
import { saveAs } from 'file-saver'
import './attachment.css'

// ============================================
// 工具函数
// ============================================

function getMediaUrl(url: string | undefined): string {
  if (!url) return ''
  // base64 编码的图片直接返回
  if (url.length > 200) return url
  return url?.startsWith('/rest') ? url : '/rest' + url
}

// ============================================
// 子组件
// ============================================

// 视频/音频展示组件
const MediaShow = ({ file, downloadFile, type }: { file: any; downloadFile: (file: any) => void; type: 'video' | 'audio' }) => {
  const [open, setOpen] = React.useState(false)

  return (
    <div className="flex items-center gap-2 p-2 border rounded-md">
      {type === 'video' ? (
        <Video className="h-5 w-5 text-slate-500" />
      ) : (
        <Music className="h-5 w-5 text-slate-500" />
      )}
      <span className="flex-1 text-sm truncate">{file.name}</span>
      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger asChild>
            <button
              className="p-1 hover:bg-slate-100 rounded"
              onClick={() => setOpen(true)}
            >
              <Eye className="h-4 w-4" />
            </button>
          </TooltipTrigger>
          <TooltipContent>
            <p>预览文件</p>
          </TooltipContent>
        </Tooltip>
      </TooltipProvider>
      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger asChild>
            <button
              className="p-1 hover:bg-slate-100 rounded"
              onClick={() => downloadFile(file)}
            >
              <Download className="h-4 w-4" />
            </button>
          </TooltipTrigger>
          <TooltipContent>
            <p>下载文件</p>
          </TooltipContent>
        </Tooltip>
      </TooltipProvider>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="max-w-3xl">
          <DialogHeader>
            <DialogTitle>{file.name}</DialogTitle>
          </DialogHeader>
          {type === 'video' ? (
            <video
              className="w-full max-h-[70vh]"
              src={file.url || file.preview}
              controls
            />
          ) : (
            <audio
              className="w-full"
              src={file.url || file.preview}
              controls
            />
          )}
        </DialogContent>
      </Dialog>
    </div>
  )
}

