  const controlType = filterSchema?.controlType || schema?.controlType
  switch (controlType) {
    case 'text':
    case 'link':
    case 'serial-number':
      return FilterText
    case 'area':
      return FilterArea
    case 'boolean':
      return FilterBool
    case 'date':
